    pub fn resolveSharedObjectInputJson(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        object_id: []const u8,
        mutable: bool,
    ) ![]u8 {
        var resolved = try self.resolveLocalObjectReference(allocator, object_id);
        defer resolved.deinit(allocator);

        const initial_shared_version = resolved.shared_initial_version orelse return error.InvalidCli;

        return try buildSharedObjectInputJson(
            allocator,
            resolved.object_id,
            initial_shared_version,
            mutable,
        );
    }

    fn buildSharedObjectInputJson(
        allocator: std.mem.Allocator,
        object_id: []const u8,
        initial_shared_version: u64,
        mutable: bool,
    ) ![]u8 {
        return try std.fmt.allocPrint(
            allocator,
            "{{\"Object\":{{\"SharedObject\":{{\"objectId\":{f},\"initialSharedVersion\":{},\"mutable\":{}}}}}}}",
            .{
                std.json.fmt(object_id, .{}),
                initial_shared_version,
                mutable,
            },
        );
    }

    const ObjectInputPreset = struct {
        object_id: []const u8,
        input_kind: ObjectInputKind,
        mutable: bool = false,
        version: ?u64 = null,
        digest: ?[]const u8 = null,
        initial_shared_version: ?u64 = null,
    };

    fn objectInputPreset(kind: ObjectPresetKind) ObjectInputPreset {
        return switch (kind) {
            .clock => .{
                .object_id = object_preset.objectId(.clock),
                .input_kind = .shared,
                .mutable = false,
                .initial_shared_version = 1,
            },
            .cetus_clmm_global_config_mainnet => .{
                .object_id = object_preset.objectId(.cetus_clmm_global_config_mainnet),
                .input_kind = .shared,
                .mutable = false,
            },
            .cetus_clmm_global_config_testnet => .{
                .object_id = object_preset.objectId(.cetus_clmm_global_config_testnet),
                .input_kind = .shared,
                .mutable = false,
            },
        };
    }

    pub fn buildGasDataJson(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        owner: []const u8,
        gas_payment_json: []const u8,
        gas_price: u64,
        gas_budget: u64,
    ) ![]u8 {
        _ = self;
        const parsed = try std.json.parseFromSlice(std.json.Value, allocator, gas_payment_json, .{});
        defer parsed.deinit();

        if (parsed.value != .array or parsed.value.array.items.len == 0) return error.InvalidCli;
        for (parsed.value.array.items) |entry| {
            if (entry != .object) return error.InvalidCli;
            const object_id = entry.object.get("objectId") orelse return error.InvalidCli;
            const version = entry.object.get("version") orelse return error.InvalidCli;
            const digest = entry.object.get("digest") orelse return error.InvalidCli;
            if (object_id != .string or digest != .string) return error.InvalidCli;
            _ = try parseUnsignedJsonValue(version);
        }

        return try std.fmt.allocPrint(
            allocator,
            "{{\"payment\":{f},\"owner\":{f},\"price\":{},\"budget\":{}}}",
            .{
                std.json.fmt(parsed.value, .{}),
                std.json.fmt(owner, .{}),
                gas_price,
                gas_budget,
            },
        );
    }

    pub const OwnedLocalProgrammableTransactionParts = struct {
        inputs_json: []u8,
        commands_json: []u8,
        sender: []u8,
        gas_data_json: []u8,
        expiration_json: ?[]u8 = null,

        pub fn deinit(self: *OwnedLocalProgrammableTransactionParts, allocator: std.mem.Allocator) void {
            allocator.free(self.inputs_json);
            allocator.free(self.commands_json);
            allocator.free(self.sender);
            allocator.free(self.gas_data_json);
            if (self.expiration_json) |value| allocator.free(value);
        }
    };

    fn stringifyJsonValueAlloc(
        allocator: std.mem.Allocator,
        value: std.json.Value,
    ) ![]u8 {
        var out = std.ArrayList(u8){};
        errdefer out.deinit(allocator);
        try out.writer(allocator).print("{f}", .{std.json.fmt(value, .{})});
        return try out.toOwnedSlice(allocator);
    }

    fn buildPureBytesInputJson(
        allocator: std.mem.Allocator,
        bytes: []const u8,
    ) ![]u8 {
        const encoded_len = std.base64.standard.Encoder.calcSize(bytes.len);
        const encoded = try allocator.alloc(u8, encoded_len);
        defer allocator.free(encoded);
        _ = std.base64.standard.Encoder.encode(encoded, bytes);
        return try std.fmt.allocPrint(
            allocator,
            "{{\"Pure\":{f}}}",
            .{std.json.fmt(encoded, .{})},
        );
    }

    fn buildPureAddressInputJson(
        allocator: std.mem.Allocator,
        address: []const u8,
    ) ![]u8 {
        const parsed = try ptb_bytes_builder.parseHexAddress32(address);
        return try buildPureBytesInputJson(allocator, &parsed);
    }

    fn buildPureU64InputJson(
        allocator: std.mem.Allocator,
        value: u64,
    ) ![]u8 {
        var bytes: [8]u8 = undefined;
        std.mem.writeInt(u64, &bytes, value, .little);
        return try buildPureBytesInputJson(allocator, &bytes);
    }

    fn parseUnsignedJsonValueAs(
        comptime T: type,
        value: std.json.Value,
    ) !T {
        return switch (value) {
            .integer => |integer| blk: {
                if (integer < 0) return error.InvalidCli;
                if (integer > std.math.maxInt(T)) return error.InvalidCli;
                break :blk @intCast(integer);
            },
            .number_string => |digits| try std.fmt.parseInt(T, digits, 10),
            .string => |digits| try std.fmt.parseInt(T, digits, 10),
            else => error.InvalidCli,
        };
    }

    fn buildPureUnsignedInputJson(
        comptime T: type,
        allocator: std.mem.Allocator,
        value: T,
    ) ![]u8 {
        var bytes: [@sizeOf(T)]u8 = undefined;
        std.mem.writeInt(T, &bytes, value, .little);
        return try buildPureBytesInputJson(allocator, &bytes);
    }

    fn buildPureBoolInputJson(
        allocator: std.mem.Allocator,
        value: bool,
    ) ![]u8 {
        return try buildPureBytesInputJson(allocator, &.{if (value) 1 else 0});
    }

    pub const LocalMoveCallParameterKind = enum {
        object,
        vector,
        address,
        signer,
        boolean,
        u8,
        u16,
        u32,
        u64,
        u128,
        u256,
        vector_u8,
        utf8_string,
        ascii_string,
        object_id,
        option,
        unsupported,
    };

    fn normalizedStructTypeArguments(
        struct_object: std.json.ObjectMap,
    ) ![]const std.json.Value {
        const type_params_value = struct_object.get("typeArguments") orelse
            struct_object.get("type_arguments") orelse
            struct_object.get("typeParams") orelse
            struct_object.get("type_params") orelse
            return &.{};
        if (type_params_value != .array) return error.InvalidCli;
        return type_params_value.array.items;
    }

    fn normalizedStructMatches(
        struct_object: std.json.ObjectMap,
        target_address: []const u8,
        target_module: []const u8,
        target_name: []const u8,
    ) !bool {
        const address_value = struct_object.get("address") orelse return error.InvalidCli;
        const module_value = struct_object.get("module") orelse return error.InvalidCli;
        const name_value = struct_object.get("name") orelse return error.InvalidCli;
        if (address_value != .string or module_value != .string or name_value != .string) return error.InvalidCli;

        const target = try ptb_bytes_builder.parseHexAddress32(target_address);
        const candidate = try ptb_bytes_builder.parseHexAddress32(address_value.string);
        return std.mem.eql(u8, &candidate, &target) and
            std.mem.eql(u8, module_value.string, target_module) and
            std.mem.eql(u8, name_value.string, target_name);
    }

    fn isKnownPureStructFamily(
        struct_object: std.json.ObjectMap,
    ) !bool {
        return try normalizedStructMatches(struct_object, "0x1", "string", "String") or
            try normalizedStructMatches(struct_object, "0x1", "ascii", "String") or
            try normalizedStructMatches(struct_object, "0x2", "object", "ID") or
            try normalizedStructMatches(struct_object, "0x1", "option", "Option");
    }

    fn normalizedTypeSupportsPureValueEncoding(
        value: std.json.Value,
    ) !bool {
        switch (value) {
            .string => |name| {
                const canonical = canonicalPrimitiveMoveTypeName(name) orelse return false;
                return !std.mem.eql(u8, canonical, "signer");
            },
            .object => |object| {
                if (object.get("Reference")) |inner| {
                    return try normalizedTypeSupportsPureValueEncoding(inner);
                }
                if (object.get("MutableReference")) |inner| {
                    return try normalizedTypeSupportsPureValueEncoding(inner);
                }
                if (object.get("TypeParameter") != null) return false;
                if (object.get("Vector")) |inner| {
                    return try normalizedTypeSupportsPureValueEncoding(inner);
                }
                if (object.get("Struct")) |struct_value| {
                    if (struct_value != .object) return false;
                    const struct_object = struct_value.object;
                    const type_params = try normalizedStructTypeArguments(struct_object);

                    if (try normalizedStructMatches(struct_object, "0x1", "string", "String")) {
                        return type_params.len == 0;
                    }
                    if (try normalizedStructMatches(struct_object, "0x1", "ascii", "String")) {
                        return type_params.len == 0;
                    }
                    if (try normalizedStructMatches(struct_object, "0x2", "object", "ID")) {
                        return type_params.len == 0;
                    }
                    if (try normalizedStructMatches(struct_object, "0x1", "option", "Option")) {
                        return type_params.len == 1 and try normalizedTypeSupportsPureValueEncoding(type_params[0]);
                    }
                }
                return false;
            },
            else => return false,
        }
    }

    fn classifyKnownPureStructType(
        value: std.json.Value,
    ) !?LocalMoveCallParameterKind {
        switch (value) {
            .object => |object| {
                if (object.get("Reference")) |inner| {
                    return try classifyKnownPureStructType(inner);
                }
                if (object.get("MutableReference")) |inner| {
                    return try classifyKnownPureStructType(inner);
                }
                const struct_value = object.get("Struct") orelse return null;
                if (struct_value != .object) return null;
                const struct_object = struct_value.object;
                const type_params = try normalizedStructTypeArguments(struct_object);

                if (try normalizedStructMatches(struct_object, "0x1", "string", "String")) {
                    return if (type_params.len == 0) .utf8_string else .unsupported;
                }
                if (try normalizedStructMatches(struct_object, "0x1", "ascii", "String")) {
                    return if (type_params.len == 0) .ascii_string else .unsupported;
                }
                if (try normalizedStructMatches(struct_object, "0x2", "object", "ID")) {
                    return if (type_params.len == 0) .object_id else .unsupported;
                }
                if (try normalizedStructMatches(struct_object, "0x1", "option", "Option")) {
                    return if (type_params.len == 1 and try normalizedTypeSupportsPureValueEncoding(type_params[0]))
                        .option
                    else
                        .unsupported;
                }
                return null;
            },
            else => return null,
        }
    }

    fn classifyNormalizedMoveType(
        allocator: std.mem.Allocator,
        value: std.json.Value,
    ) !?LocalMoveCallParameterKind {
        switch (value) {
            .string => |name| {
                if (std.ascii.eqlIgnoreCase(name, "address")) return .address;
                if (std.ascii.eqlIgnoreCase(name, "signer")) return .signer;
                if (std.ascii.eqlIgnoreCase(name, "bool")) return .boolean;
                if (std.ascii.eqlIgnoreCase(name, "u8")) return .u8;
                if (std.ascii.eqlIgnoreCase(name, "u16")) return .u16;
                if (std.ascii.eqlIgnoreCase(name, "u32")) return .u32;
                if (std.ascii.eqlIgnoreCase(name, "u64")) return .u64;
                if (std.ascii.eqlIgnoreCase(name, "u128")) return .u128;
                if (std.ascii.eqlIgnoreCase(name, "u256")) return .u256;
                return .unsupported;
            },
            .object => |object| {
                if (object.get("Reference")) |inner| {
                    return try classifyNormalizedMoveType(allocator, inner);
                }
                if (object.get("MutableReference")) |inner| {
                    return try classifyNormalizedMoveType(allocator, inner);
                }
                if (object.get("Vector")) |inner| {
                    const nested = try classifyNormalizedMoveType(allocator, inner);
                    if (nested == .u8) return .vector_u8;
                    return .vector;
                }
                if (object.get("Struct")) |struct_value| {
                    if (struct_value != .object) return .unsupported;
                    if (try normalizedStructMatches(struct_value.object, "0x2", "tx_context", "TxContext")) {
                        return null;
                    }
                    if (try classifyKnownPureStructType(value)) |kind| return kind;
                    if (try isKnownPureStructFamily(struct_value.object)) return .unsupported;
                    return .object;
                }
                return .unsupported;
            },
            else => return .unsupported,
        }
    }

    fn canonicalPrimitiveMoveTypeName(name: []const u8) ?[]const u8 {
        if (std.ascii.eqlIgnoreCase(name, "bool")) return "bool";
        if (std.ascii.eqlIgnoreCase(name, "u8")) return "u8";
        if (std.ascii.eqlIgnoreCase(name, "u16")) return "u16";
        if (std.ascii.eqlIgnoreCase(name, "u32")) return "u32";
        if (std.ascii.eqlIgnoreCase(name, "u64")) return "u64";
        if (std.ascii.eqlIgnoreCase(name, "u128")) return "u128";
        if (std.ascii.eqlIgnoreCase(name, "u256")) return "u256";
        if (std.ascii.eqlIgnoreCase(name, "address")) return "address";
        if (std.ascii.eqlIgnoreCase(name, "signer")) return "signer";
        return null;
    }

    fn normalizedMoveTypeContainsTypeParameter(value: std.json.Value) bool {
        return switch (value) {
            .object => |object| blk: {
                if (object.get("TypeParameter") != null) break :blk true;
                if (object.get("Reference")) |inner| break :blk normalizedMoveTypeContainsTypeParameter(inner);
                if (object.get("MutableReference")) |inner| break :blk normalizedMoveTypeContainsTypeParameter(inner);
                if (object.get("Vector")) |inner| break :blk normalizedMoveTypeContainsTypeParameter(inner);
                if (object.get("Struct")) |struct_value| {
                    if (struct_value != .object) break :blk false;
                    const type_params_value = struct_value.object.get("typeArguments") orelse
                        struct_value.object.get("type_arguments") orelse
                        struct_value.object.get("typeParams") orelse
                        struct_value.object.get("type_params");
                    if (type_params_value) |type_params| {
                        if (type_params != .array) break :blk false;
                        for (type_params.array.items) |item| {
                            if (normalizedMoveTypeContainsTypeParameter(item)) break :blk true;
                        }
                    }
                }
                break :blk false;
            },
            else => false,
        };
    }

    fn writeCanonicalNormalizedMoveTypeJson(
        allocator: std.mem.Allocator,
        writer: anytype,
        value: std.json.Value,
    ) !void {
        switch (value) {
            .string => |name| {
                const canonical = canonicalPrimitiveMoveTypeName(name) orelse return error.InvalidCli;
                try writer.print("{f}", .{std.json.fmt(canonical, .{})});
            },
            .object => |object| {
                if (object.get("Reference")) |inner| {
                    return try writeCanonicalNormalizedMoveTypeJson(allocator, writer, inner);
                }
                if (object.get("MutableReference")) |inner| {
                    return try writeCanonicalNormalizedMoveTypeJson(allocator, writer, inner);
                }
                if (object.get("TypeParameter") != null) return error.InvalidCli;
                if (object.get("Vector")) |inner| {
                    try writer.writeAll("{\"Vector\":");
                    try writeCanonicalNormalizedMoveTypeJson(allocator, writer, inner);
                    try writer.writeAll("}");
                    return;
                }
                if (object.get("Struct")) |struct_value| {
                    if (struct_value != .object) return error.InvalidCli;
                    const address_value = struct_value.object.get("address") orelse return error.InvalidCli;
                    const module_value = struct_value.object.get("module") orelse return error.InvalidCli;
                    const name_value = struct_value.object.get("name") orelse return error.InvalidCli;
                    if (address_value != .string or module_value != .string or name_value != .string) return error.InvalidCli;

                    try writer.print(
                        "{{\"Struct\":{{\"address\":{f},\"module\":{f},\"name\":{f},\"typeParams\":[",
                        .{
                            std.json.fmt(address_value.string, .{}),
                            std.json.fmt(module_value.string, .{}),
                            std.json.fmt(name_value.string, .{}),
                        },
                    );

                    const type_params_value = struct_value.object.get("typeArguments") orelse
                        struct_value.object.get("type_arguments") orelse
                        struct_value.object.get("typeParams") orelse
                        struct_value.object.get("type_params");
                    if (type_params_value) |type_params| {
                        if (type_params != .array) return error.InvalidCli;
                        for (type_params.array.items, 0..) |item, index| {
                            if (index != 0) try writer.writeAll(",");
                            try writeCanonicalNormalizedMoveTypeJson(allocator, writer, item);
                        }
                    }

                    try writer.writeAll("]}}");
                    return;
                }
                return error.InvalidCli;
            },
            else => return error.InvalidCli,
        }
    }

    fn canonicalNormalizedMoveTypeJson(
        allocator: std.mem.Allocator,
        value: std.json.Value,
    ) ![]u8 {
        var out = std.ArrayList(u8){};
        errdefer out.deinit(allocator);
        try writeCanonicalNormalizedMoveTypeJson(allocator, out.writer(allocator), value);
        return try out.toOwnedSlice(allocator);
    }

    fn parseMoveTypeTextCanonicalJson(
        allocator: std.mem.Allocator,
        raw_text: []const u8,
    ) ![]u8 {
        const Parser = struct {
            allocator: std.mem.Allocator,
            input: []const u8,
            index: usize = 0,

            fn skipWhitespace(self: *@This()) void {
                while (self.index < self.input.len and std.ascii.isWhitespace(self.input[self.index])) : (self.index += 1) {}
            }

            fn parseSegment(self: *@This()) ![]const u8 {
                self.skipWhitespace();
                const start = self.index;
                while (self.index < self.input.len) : (self.index += 1) {
                    const char = self.input[self.index];
                    if (char == '<' or char == '>' or char == ',' or char == ':' or std.ascii.isWhitespace(char)) break;
                }
                if (start == self.index) return error.InvalidCli;
                return self.input[start..self.index];
            }

            fn consumeChar(self: *@This(), expected: u8) bool {
                self.skipWhitespace();
                if (self.index >= self.input.len or self.input[self.index] != expected) return false;
                self.index += 1;
                return true;
            }

            fn expectChar(self: *@This(), expected: u8) !void {
                if (!self.consumeChar(expected)) return error.InvalidCli;
            }

            fn consumeDoubleColon(self: *@This()) bool {
                self.skipWhitespace();
                if (self.index + 1 >= self.input.len) return false;
                if (self.input[self.index] != ':' or self.input[self.index + 1] != ':') return false;
                self.index += 2;
                return true;
            }

            fn expectDoubleColon(self: *@This()) !void {
                if (!self.consumeDoubleColon()) return error.InvalidCli;
            }

            fn parseStructTypeJson(
                self: *@This(),
                address: []const u8,
                module: []const u8,
                name: []const u8,
            ) anyerror![]u8 {
                var type_args = std.ArrayListUnmanaged([]u8){};
                defer {
                    for (type_args.items) |item| self.allocator.free(item);
                    type_args.deinit(self.allocator);
                }

                if (self.consumeChar('<')) {
                    while (true) {
                        try type_args.append(self.allocator, try self.parseTypeJson());
                        if (self.consumeChar(',')) continue;
                        try self.expectChar('>');
                        break;
                    }
                }

                var out = std.ArrayList(u8){};
                errdefer out.deinit(self.allocator);
                const writer = out.writer(self.allocator);
                try writer.print(
                    "{{\"Struct\":{{\"address\":{f},\"module\":{f},\"name\":{f},\"typeParams\":[",
                    .{
                        std.json.fmt(address, .{}),
                        std.json.fmt(module, .{}),
                        std.json.fmt(name, .{}),
                    },
                );
                for (type_args.items, 0..) |item, index| {
                    if (index != 0) try writer.writeAll(",");
                    try writer.writeAll(item);
                }
                try writer.writeAll("]}}");
                return try out.toOwnedSlice(self.allocator);
            }

            fn parseTypeJson(self: *@This()) anyerror![]u8 {
                const head = try self.parseSegment();
                if (canonicalPrimitiveMoveTypeName(head)) |primitive| {
                    return try std.fmt.allocPrint(self.allocator, "{f}", .{std.json.fmt(primitive, .{})});
                }

                if (std.ascii.eqlIgnoreCase(head, "vector")) {
                    try self.expectChar('<');
                    const inner = try self.parseTypeJson();
                    defer self.allocator.free(inner);
                    try self.expectChar('>');
                    return try std.fmt.allocPrint(self.allocator, "{{\"Vector\":{s}}}", .{inner});
                }

                try self.expectDoubleColon();
                const module = try self.parseSegment();
                try self.expectDoubleColon();
                const name = try self.parseSegment();
                return try self.parseStructTypeJson(head, module, name);
            }
        };

        var parser = Parser{
            .allocator = allocator,
            .input = std.mem.trim(u8, raw_text, " \n\r\t"),
        };
        const parsed = try parser.parseTypeJson();
        errdefer allocator.free(parsed);
        parser.skipWhitespace();
        if (parser.index != parser.input.len) return error.InvalidCli;
        return parsed;
    }

    fn canonicalMoveTypeArgumentJson(
        allocator: std.mem.Allocator,
        value: std.json.Value,
    ) ![]u8 {
        return switch (value) {
            .string => |text| try parseMoveTypeTextCanonicalJson(allocator, text),
            .object => try canonicalNormalizedMoveTypeJson(allocator, value),
            else => error.InvalidCli,
        };
    }

    fn canonicalMoveTypeArgumentsJson(
        allocator: std.mem.Allocator,
        items: []const std.json.Value,
    ) ![]u8 {
        var out = std.ArrayList(u8){};
        errdefer out.deinit(allocator);
        const writer = out.writer(allocator);
        try writer.writeAll("[");
        for (items, 0..) |item, index| {
            const canonical = try canonicalMoveTypeArgumentJson(allocator, item);
            defer allocator.free(canonical);
            if (index != 0) try writer.writeAll(",");
            try writer.writeAll(canonical);
        }
        try writer.writeAll("]");
        return try out.toOwnedSlice(allocator);
    }

    fn parseNormalizedTypeParameterIndex(
        value: std.json.Value,
    ) !usize {
        return switch (value) {
            .integer => |number| blk: {
                if (number < 0) return error.InvalidCli;
                break :blk @intCast(number);
            },
            .string => |text| try std.fmt.parseInt(usize, text, 10),
            else => error.InvalidCli,
        };
    }

    fn substituteNormalizedMoveTypeJson(
        allocator: std.mem.Allocator,
        value: std.json.Value,
        raw_type_arguments: []const std.json.Value,
    ) ![]u8 {
        switch (value) {
            .string => |name| {
                const canonical = canonicalPrimitiveMoveTypeName(name) orelse return error.InvalidCli;
                return try std.fmt.allocPrint(allocator, "{f}", .{std.json.fmt(canonical, .{})});
            },
            .object => |object| {
                if (object.get("Reference")) |inner| {
                    const resolved = try substituteNormalizedMoveTypeJson(allocator, inner, raw_type_arguments);
                    defer allocator.free(resolved);
                    return try std.fmt.allocPrint(allocator, "{{\"Reference\":{s}}}", .{resolved});
                }
                if (object.get("MutableReference")) |inner| {
                    const resolved = try substituteNormalizedMoveTypeJson(allocator, inner, raw_type_arguments);
                    defer allocator.free(resolved);
                    return try std.fmt.allocPrint(allocator, "{{\"MutableReference\":{s}}}", .{resolved});
                }
                if (object.get("Vector")) |inner| {
                    const resolved = try substituteNormalizedMoveTypeJson(allocator, inner, raw_type_arguments);
                    defer allocator.free(resolved);
                    return try std.fmt.allocPrint(allocator, "{{\"Vector\":{s}}}", .{resolved});
                }
                if (object.get("TypeParameter")) |raw_index| {
                    const index = try parseNormalizedTypeParameterIndex(raw_index);
                    if (index >= raw_type_arguments.len) return error.InvalidCli;
                    return try canonicalMoveTypeArgumentJson(allocator, raw_type_arguments[index]);
                }
                if (object.get("Struct")) |struct_value| {
                    if (struct_value != .object) return error.InvalidCli;
                    const address_value = struct_value.object.get("address") orelse return error.InvalidCli;
                    const module_value = struct_value.object.get("module") orelse return error.InvalidCli;
                    const name_value = struct_value.object.get("name") orelse return error.InvalidCli;
                    if (address_value != .string or module_value != .string or name_value != .string) return error.InvalidCli;

                    var out = std.ArrayList(u8){};
                    errdefer out.deinit(allocator);
                    const writer = out.writer(allocator);
                    try writer.print(
                        "{{\"Struct\":{{\"address\":{f},\"module\":{f},\"name\":{f},\"typeParams\":[",
                        .{
                            std.json.fmt(address_value.string, .{}),
                            std.json.fmt(module_value.string, .{}),
                            std.json.fmt(name_value.string, .{}),
                        },
                    );

                    const type_params = try normalizedStructTypeArguments(struct_value.object);
                    for (type_params, 0..) |item, index| {
                        const resolved = try substituteNormalizedMoveTypeJson(allocator, item, raw_type_arguments);
                        defer allocator.free(resolved);
                        if (index != 0) try writer.writeAll(",");
                        try writer.writeAll(resolved);
                    }
                    try writer.writeAll("]}}");
                    return try out.toOwnedSlice(allocator);
                }
                return error.InvalidCli;
            },
            else => return error.InvalidCli,
        }
    }

    fn appendUleb128(
        out: *std.ArrayList(u8),
        allocator: std.mem.Allocator,
        value: usize,
    ) !void {
        var remaining = value;
        while (true) {
            var byte: u8 = @intCast(remaining & 0x7f);
            remaining >>= 7;
            if (remaining != 0) byte |= 0x80;
            try out.append(allocator, byte);
            if (remaining == 0) return;
        }
    }

    fn appendLengthPrefixedBytes(
        out: *std.ArrayList(u8),
        allocator: std.mem.Allocator,
        bytes: []const u8,
    ) !void {
        try appendUleb128(out, allocator, bytes.len);
        try out.appendSlice(allocator, bytes);
    }

    fn appendNormalizedPureValueBytes(
        allocator: std.mem.Allocator,
        out: *std.ArrayList(u8),
        value: std.json.Value,
        parameter_type: std.json.Value,
    ) !void {
        switch (parameter_type) {
            .string => |name| {
                const canonical = canonicalPrimitiveMoveTypeName(name) orelse return error.InvalidCli;
                if (std.mem.eql(u8, canonical, "bool")) {
                    if (value != .bool) return error.InvalidCli;
                    try out.append(allocator, if (value.bool) 1 else 0);
                    return;
                }
                if (std.mem.eql(u8, canonical, "u8")) {
                    try out.append(allocator, try parseUnsignedJsonValueAs(u8, value));
                    return;
                }
                if (std.mem.eql(u8, canonical, "u16")) {
                    var bytes: [2]u8 = undefined;
                    std.mem.writeInt(u16, &bytes, try parseUnsignedJsonValueAs(u16, value), .little);
                    try out.appendSlice(allocator, &bytes);
                    return;
                }
                if (std.mem.eql(u8, canonical, "u32")) {
                    var bytes: [4]u8 = undefined;
                    std.mem.writeInt(u32, &bytes, try parseUnsignedJsonValueAs(u32, value), .little);
                    try out.appendSlice(allocator, &bytes);
                    return;
                }
                if (std.mem.eql(u8, canonical, "u64")) {
                    var bytes: [8]u8 = undefined;
                    std.mem.writeInt(u64, &bytes, try parseUnsignedJsonValueAs(u64, value), .little);
                    try out.appendSlice(allocator, &bytes);
                    return;
                }
                if (std.mem.eql(u8, canonical, "u128")) {
                    var bytes: [16]u8 = undefined;
                    std.mem.writeInt(u128, &bytes, try parseUnsignedJsonValueAs(u128, value), .little);
                    try out.appendSlice(allocator, &bytes);
                    return;
                }
                if (std.mem.eql(u8, canonical, "u256")) {
                    var bytes: [32]u8 = undefined;
                    std.mem.writeInt(u256, &bytes, try parseUnsignedJsonValueAs(u256, value), .little);
                    try out.appendSlice(allocator, &bytes);
                    return;
                }
                if (std.mem.eql(u8, canonical, "address")) {
                    if (value != .string) return error.InvalidCli;
                    const address = try ptb_bytes_builder.parseHexAddress32(value.string);
                    try out.appendSlice(allocator, &address);
                    return;
                }
                return error.InvalidCli;
            },
            .object => |object| {
                if (object.get("Reference")) |inner| {
                    return try appendNormalizedPureValueBytes(allocator, out, value, inner);
                }
                if (object.get("MutableReference")) |inner| {
                    return try appendNormalizedPureValueBytes(allocator, out, value, inner);
                }
                if (object.get("Vector")) |inner| {
                    if ((try classifyNormalizedMoveType(allocator, inner)) == .u8) {
                        const bytes = try ptb_bytes_builder.parseRawBytesJsonValue(allocator, value);
                        defer allocator.free(bytes);
                        return try appendLengthPrefixedBytes(out, allocator, bytes);
                    }
                    if (value != .array) return error.InvalidCli;
                    try appendUleb128(out, allocator, value.array.items.len);
                    for (value.array.items) |item| {
                        try appendNormalizedPureValueBytes(allocator, out, item, inner);
                    }
                    return;
                }
                const struct_kind = (try classifyKnownPureStructType(parameter_type)) orelse return error.InvalidCli;
                const struct_value = object.get("Struct") orelse return error.InvalidCli;
                if (struct_value != .object) return error.InvalidCli;
                const type_params = try normalizedStructTypeArguments(struct_value.object);

                switch (struct_kind) {
                    .utf8_string => {
                        if (value != .string) return error.InvalidCli;
                        return try appendLengthPrefixedBytes(out, allocator, value.string);
                    },
                    .ascii_string => {
                        if (value != .string) return error.InvalidCli;
                        for (value.string) |char| {
                            if (char > 0x7f) return error.InvalidCli;
                        }
                        return try appendLengthPrefixedBytes(out, allocator, value.string);
                    },
                    .object_id => {
                        if (value != .string) return error.InvalidCli;
                        const address = try ptb_bytes_builder.parseHexAddress32(value.string);
                        try out.appendSlice(allocator, &address);
                        return;
                    },
                    .option => {
                        if (type_params.len != 1) return error.InvalidCli;
                        if (value == .null) {
                            return try appendUleb128(out, allocator, 0);
                        }
                        try appendUleb128(out, allocator, 1);
                        return try appendNormalizedPureValueBytes(allocator, out, value, type_params[0]);
                    },
                    else => return error.InvalidCli,
                }
            },
            else => return error.InvalidCli,
        }
    }

    fn buildPureNormalizedValueInputJson(
        allocator: std.mem.Allocator,
        value: std.json.Value,
        parameter_type: std.json.Value,
    ) ![]u8 {
        var bytes = std.ArrayList(u8){};
        defer bytes.deinit(allocator);
        try appendNormalizedPureValueBytes(allocator, &bytes, value, parameter_type);
        return try buildPureBytesInputJson(allocator, bytes.items);
    }

