    fn jsonValueContainsSharedDiscoveryCandidate(text: []const u8) bool {
        return std.mem.startsWith(u8, text, "0x") and text.len > 2;
    }

    fn appendDiscoveredObjectIdsFromJsonValue(
        allocator: std.mem.Allocator,
        collected: *std.ArrayList([]u8),
        value: std.json.Value,
        max_items: usize,
    ) !void {
        if (collected.items.len >= max_items) return;

        switch (value) {
            .string => |text| {
                if (!jsonValueContainsSharedDiscoveryCandidate(text)) return;
                for (collected.items) |existing| {
                    if (std.mem.eql(u8, existing, text)) return;
                }
                try collected.append(allocator, try allocator.dupe(u8, text));
            },
            .array => |array| {
                for (array.items) |item| {
                    if (collected.items.len >= max_items) return;
                    try appendDiscoveredObjectIdsFromJsonValue(allocator, collected, item, max_items);
                }
            },
            .object => |object| {
                var iterator = object.iterator();
                while (iterator.next()) |entry| {
                    if (collected.items.len >= max_items) return;
                    try appendDiscoveredObjectIdsFromJsonValue(allocator, collected, entry.value_ptr.*, max_items);
                }
            },
            else => {},
        }
    }

    fn discoverSharedObjectCandidatesFromModuleEvents(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        event_package_id: []const u8,
        event_module_name: []const u8,
        signature: []const u8,
    ) ![]move_result.SharedMoveObjectCandidate {
        const struct_type = trimMoveReferenceSignature(signature);

        var page = try self.getEventsPageWithRequest(allocator, .{
            .filter = .{
                .move_module = .{
                    .package = event_package_id,
                    .module = event_module_name,
                },
            },
            .limit = 20,
            .descending_order = true,
        });
        defer page.deinit(allocator);

        var discovered_ids = std.ArrayList([]u8).empty;
        defer {
            for (discovered_ids.items) |value| allocator.free(value);
            discovered_ids.deinit(allocator);
        }

        for (page.entries) |entry| {
            const parsed_json = entry.parsed_json orelse continue;
            const parsed = std.json.parseFromSlice(std.json.Value, allocator, parsed_json, .{}) catch continue;
            defer parsed.deinit();
            try appendDiscoveredObjectIdsFromJsonValue(allocator, &discovered_ids, parsed.value, 16);
            if (discovered_ids.items.len >= 16) break;
        }

        var candidates = std.ArrayList(move_result.SharedMoveObjectCandidate).empty;
        errdefer {
            for (candidates.items) |*value| value.deinit(allocator);
            candidates.deinit(allocator);
        }

        for (discovered_ids.items) |object_id| {
            var summary = self.getObjectAndSummarizeWithOptions(
                allocator,
                object_id,
                .{
                    .show_type = true,
                    .show_owner = true,
                },
            ) catch continue;
            defer summary.deinit(allocator);

            if (summary.status != .found) continue;
            if ((summary.owner_kind orelse .unknown) != .shared) continue;
            const type_name = summary.type_name orelse continue;
            if (!std.mem.eql(u8, type_name, struct_type)) continue;
            const owner_value = summary.owner_value orelse continue;
            const initial_shared_version = std.fmt.parseInt(u64, owner_value, 10) catch continue;
            const shared_token = summary.shared_object_input_select_token orelse continue;
            const mutable_shared_token = summary.mutable_shared_object_input_select_token orelse continue;

            var already_present = false;
            for (candidates.items) |candidate| {
                if (std.mem.eql(u8, candidate.object_id, object_id)) {
                    already_present = true;
                    break;
                }
            }
            if (already_present) continue;

            try candidates.append(allocator, .{
                .object_id = try allocator.dupe(u8, object_id),
                .type_name = try allocator.dupe(u8, type_name),
                .initial_shared_version = initial_shared_version,
                .shared_object_input_select_token = try allocator.dupe(u8, shared_token),
                .mutable_shared_object_input_select_token = try allocator.dupe(u8, mutable_shared_token),
            });
        }

        return try candidates.toOwnedSlice(allocator);
    }

    fn discoverOwnedObjectCandidates(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        owner: []const u8,
        struct_type: []const u8,
    ) ![]move_result.OwnedMoveObjectCandidate {
        if (coinTypeFromCoinStructType(struct_type)) |coin_type| {
            var coin_page = try self.getAllCoinsWithRequest(allocator, owner, .{
                .coin_type = coin_type,
                .limit = 20,
            });
            defer coin_page.deinit(allocator);

            var coin_candidates = std.ArrayList(move_result.OwnedMoveObjectCandidate).empty;
            errdefer {
                for (coin_candidates.items) |*value| value.deinit(allocator);
                coin_candidates.deinit(allocator);
            }

            for (coin_page.entries) |entry| {
                const object_id = entry.coin_object_id orelse continue;
                const version = entry.version orelse continue;
                const digest = entry.digest orelse continue;
                try coin_candidates.append(allocator, .{
                    .object_id = try allocator.dupe(u8, object_id),
                    .version = version,
                    .digest = try allocator.dupe(u8, digest),
                    .balance = entry.balanceU64(),
                    .type_name = try allocator.dupe(u8, struct_type),
                    .owner_value = try allocator.dupe(u8, owner),
                    .object_input_select_token = try buildExactImmOrOwnedObjectInputSelectToken(
                        allocator,
                        object_id,
                        version,
                        digest,
                    ),
                });
            }

            return try coin_candidates.toOwnedSlice(allocator);
        }

        var page = try self.getOwnedObjectsPageWithRequest(allocator, owner, .{
            .filter = .{ .struct_type = struct_type },
            .options = .{
                .typed = .{
                    .show_type = true,
                    .show_owner = true,
                },
            },
            .limit = 5,
        });
        defer page.deinit(allocator);

        var candidates = std.ArrayList(move_result.OwnedMoveObjectCandidate).empty;
        errdefer {
            for (candidates.items) |*value| value.deinit(allocator);
            candidates.deinit(allocator);
        }

        for (page.entries) |entry| {
            if (entry.status != .found) continue;
            const object_id = entry.object_id orelse continue;
            const version = entry.version orelse continue;
            const digest = entry.digest orelse continue;
            try candidates.append(allocator, .{
                .object_id = try allocator.dupe(u8, object_id),
                .version = version,
                .digest = try allocator.dupe(u8, digest),
                .balance = null,
                .type_name = if (entry.type_name) |value| try allocator.dupe(u8, value) else null,
                .owner_value = if (entry.owner_value) |value| try allocator.dupe(u8, value) else null,
                .object_input_select_token = try buildExactImmOrOwnedObjectInputSelectToken(
                    allocator,
                    object_id,
                    version,
                    digest,
                ),
            });
        }

        return try candidates.toOwnedSlice(allocator);
    }

    fn buildMoveFunctionTypeArgsTemplateJson(
        allocator: std.mem.Allocator,
        type_parameter_count: usize,
    ) ![]u8 {
        var output = std.ArrayList(u8){};
        defer output.deinit(allocator);

        const writer = output.writer(allocator);
        try writer.writeAll("[");
        for (0..type_parameter_count) |index| {
            if (index != 0) try writer.writeAll(",");
            try writer.print("\"<T{d}>\"", .{index});
        }
        try writer.writeAll("]");
        return output.toOwnedSlice(allocator);
    }

    fn buildMoveFunctionArgsTemplateJson(
        allocator: std.mem.Allocator,
        parameters: []const move_result.OwnedMoveParameterSummary,
    ) ![]u8 {
        return try buildMoveFunctionArgsJson(allocator, parameters, false);
    }

    fn buildMoveFunctionArgsJson(
        allocator: std.mem.Allocator,
        parameters: []const move_result.OwnedMoveParameterSummary,
        prefer_auto_selected: bool,
    ) ![]u8 {
        var output = std.ArrayList(u8){};
        defer output.deinit(allocator);

        const writer = output.writer(allocator);
        try writer.writeAll("[");
        var needs_separator = false;
        for (parameters) |parameter| {
            if (parameter.omitted_from_explicit_args) continue;
            const placeholder = if (prefer_auto_selected)
                parameter.explicit_arg_json orelse parameter.auto_selected_arg_json orelse parameter.placeholder_json orelse continue
            else
                parameter.placeholder_json orelse continue;
            if (needs_separator) try writer.writeAll(",");
            try writer.writeAll(placeholder);
            needs_separator = true;
        }
        try writer.writeAll("]");
        return output.toOwnedSlice(allocator);
    }

    fn buildAutoSelectedVectorArgJson(
        allocator: std.mem.Allocator,
        candidates: []const move_result.OwnedMoveObjectCandidate,
    ) !?[]u8 {
        if (candidates.len == 0) return null;

        var output = std.ArrayList(u8){};
        defer output.deinit(allocator);
        const writer = output.writer(allocator);
        try writer.writeAll("[");
        for (candidates, 0..) |candidate, index| {
            if (index != 0) try writer.writeAll(",");
            try writer.print("{f}", .{std.json.fmt(candidate.object_input_select_token, .{})});
        }
        try writer.writeAll("]");
        return try output.toOwnedSlice(allocator);
    }

    fn buildAutoSelectedScalarArgJson(
        allocator: std.mem.Allocator,
        token: []const u8,
    ) ![]u8 {
        return try std.fmt.allocPrint(allocator, "{f}", .{std.json.fmt(token, .{})});
    }

    fn buildJsonFragmentFromJsonValue(
        allocator: std.mem.Allocator,
        value: std.json.Value,
    ) ![]u8 {
        return try std.fmt.allocPrint(allocator, "{f}", .{std.json.fmt(value, .{})});
    }

    fn jsonValueLooksLikeObjectArgument(value: std.json.Value) bool {
        if (value != .string) return false;
        const trimmed = std.mem.trim(u8, value.string, " \t\r\n");
        return std.mem.startsWith(u8, trimmed, "select:") or
            std.mem.startsWith(u8, trimmed, "sel:") or
            std.mem.startsWith(u8, trimmed, "0x") or
            std.mem.startsWith(u8, trimmed, "@0x") or
            std.mem.startsWith(u8, trimmed, "obj:");
    }

    fn moveParameterSupportsSparseExplicitArg(parameter: move_result.OwnedMoveParameterSummary) bool {
        if (parameter.omitted_from_explicit_args) return false;
        const lowering_kind = parameter.lowering_kind orelse return false;
        if (std.mem.eql(u8, lowering_kind, "object")) return false;
        if (std.mem.eql(u8, lowering_kind, "vector") and concreteVectorObjectStructTypeFromSignature(parameter.signature) != null) {
            return false;
        }
        return true;
    }

    fn applyExplicitMoveFunctionArgsToParameters(
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
        arguments_json: []const u8,
    ) !void {
        const parsed = try std.json.parseFromSlice(std.json.Value, allocator, arguments_json, .{});
        defer parsed.deinit();
        if (parsed.value != .array) return error.InvalidCli;

        const explicit_args = parsed.value.array.items;
        if (explicit_args.len == 0) return;

        var explicit_parameter_count: usize = 0;
        var sparse_parameter_count: usize = 0;
        for (parameters) |parameter| {
            if (parameter.omitted_from_explicit_args) continue;
            explicit_parameter_count += 1;
            if (moveParameterSupportsSparseExplicitArg(parameter)) sparse_parameter_count += 1;
        }

        const use_sparse_mapping = blk: {
            if (explicit_args.len >= explicit_parameter_count) break :blk false;
            if (explicit_args.len > sparse_parameter_count) break :blk false;
            for (explicit_args) |value| {
                if (jsonValueLooksLikeObjectArgument(value)) break :blk false;
            }
            break :blk true;
        };

        var mapped_args: usize = 0;
        for (parameters) |*parameter| {
            if (parameter.omitted_from_explicit_args) continue;
            if (use_sparse_mapping and !moveParameterSupportsSparseExplicitArg(parameter.*)) continue;
            if (mapped_args >= explicit_args.len) break;
            parameter.explicit_arg_json = try buildJsonFragmentFromJsonValue(
                allocator,
                explicit_args[mapped_args],
            );
            mapped_args += 1;
        }

        if (mapped_args != explicit_args.len) return error.InvalidCli;
    }

    fn applyExplicitIndexedMoveFunctionArgsToParameters(
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
        indexed_arguments_json: []const u8,
    ) !void {
        const parsed = try std.json.parseFromSlice(std.json.Value, allocator, indexed_arguments_json, .{});
        defer parsed.deinit();
        if (parsed.value != .array) return error.InvalidCli;

        var seen = std.AutoHashMap(usize, void).init(allocator);
        defer seen.deinit();

        for (parsed.value.array.items) |entry| {
            if (entry != .object) return error.InvalidCli;
            const index_value = entry.object.get("index") orelse return error.InvalidCli;
            const raw_value = entry.object.get("value") orelse return error.InvalidCli;

            const parameter_index: usize = switch (index_value) {
                .integer => |number| blk: {
                    if (number < 0) return error.InvalidCli;
                    break :blk @as(usize, @intCast(number));
                },
                else => return error.InvalidCli,
            };

            if (parameter_index >= parameters.len) return error.InvalidCli;
            const seen_entry = try seen.getOrPut(parameter_index);
            if (seen_entry.found_existing) return error.InvalidCli;

            const parameter = &parameters[parameter_index];
            if (parameter.omitted_from_explicit_args) return error.InvalidCli;

            const fragment = try buildJsonFragmentFromJsonValue(allocator, raw_value);
            if (parameter.explicit_arg_json) |old_value| allocator.free(old_value);
            parameter.explicit_arg_json = fragment;
        }
    }

    fn buildExplicitMoveFunctionObjectArgJson(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        parameter: move_result.OwnedMoveParameterSummary,
        object_id: []const u8,
    ) ![]u8 {
        if (!std.mem.eql(u8, parameter.lowering_kind orelse "", "object")) return error.InvalidCli;

        var summary = try self.getObjectAndSummarizeWithOptions(
            allocator,
            object_id,
            objectDataOptionsForSummaries(.{}),
        );
        defer summary.deinit(allocator);
        if (summary.status != .found) return error.SelectionNotFound;

        const token = switch (summary.owner_kind orelse .unknown) {
            .shared => blk: {
                if (!isMoveReferenceSignature(parameter.signature)) return error.InvalidCli;
                break :blk if (isMoveMutableReferenceSignature(parameter.signature))
                    summary.mutable_shared_object_input_select_token
                else
                    summary.shared_object_input_select_token;
            },
            .address_owner, .object_owner, .immutable => summary.imm_or_owned_object_input_select_token,
            .unknown => null,
        } orelse return error.InvalidCli;

        return try buildAutoSelectedScalarArgJson(allocator, token);
    }

    fn buildExplicitMoveFunctionVectorObjectArgJson(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        parameter: move_result.OwnedMoveParameterSummary,
        object_id_values: []const std.json.Value,
    ) ![]u8 {
        if (!std.mem.eql(u8, parameter.lowering_kind orelse "", "vector")) return error.InvalidCli;
        if (concreteVectorObjectStructTypeFromSignature(parameter.signature) == null) return error.InvalidCli;

        var output = std.ArrayList(u8){};
        defer output.deinit(allocator);
        const writer = output.writer(allocator);
        try writer.writeAll("[");
        for (object_id_values, 0..) |value, index| {
            if (value != .string) return error.InvalidCli;

            var summary = try self.getObjectAndSummarizeWithOptions(
                allocator,
                value.string,
                objectDataOptionsForSummaries(.{}),
            );
            defer summary.deinit(allocator);
            if (summary.status != .found) return error.SelectionNotFound;

            const token = switch (summary.owner_kind orelse .unknown) {
                .address_owner, .object_owner, .immutable => summary.imm_or_owned_object_input_select_token,
                .shared, .unknown => null,
            } orelse return error.InvalidCli;

            if (index != 0) try writer.writeAll(",");
            try writer.print("{f}", .{std.json.fmt(token, .{})});
        }
        try writer.writeAll("]");
        return try output.toOwnedSlice(allocator);
    }

    fn applyExplicitIndexedObjectMoveFunctionArgsToParameters(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
        indexed_object_arguments_json: []const u8,
    ) !void {
        const parsed = try std.json.parseFromSlice(std.json.Value, allocator, indexed_object_arguments_json, .{});
        defer parsed.deinit();
        if (parsed.value != .array) return error.InvalidCli;

        var seen = std.AutoHashMap(usize, void).init(allocator);
        defer seen.deinit();

        for (parsed.value.array.items) |entry| {
            if (entry != .object) return error.InvalidCli;
            const index_value = entry.object.get("index") orelse return error.InvalidCli;
            const object_id_value = entry.object.get("value") orelse return error.InvalidCli;

            const parameter_index: usize = switch (index_value) {
                .integer => |number| blk: {
                    if (number < 0) return error.InvalidCli;
                    break :blk @as(usize, @intCast(number));
                },
                else => return error.InvalidCli,
            };

            if (parameter_index >= parameters.len) return error.InvalidCli;
            const seen_entry = try seen.getOrPut(parameter_index);
            if (seen_entry.found_existing) return error.InvalidCli;

            const parameter = &parameters[parameter_index];
            if (parameter.omitted_from_explicit_args) return error.InvalidCli;
            if (parameter.explicit_arg_json != null) return error.InvalidCli;

            parameter.explicit_arg_json = switch (object_id_value) {
                .string => if (std.mem.eql(u8, parameter.lowering_kind orelse "", "vector"))
                    try self.buildExplicitMoveFunctionVectorObjectArgJson(
                        allocator,
                        parameter.*,
                        &.{object_id_value},
                    )
                else
                    try self.buildExplicitMoveFunctionObjectArgJson(
                        allocator,
                        parameter.*,
                        object_id_value.string,
                    ),
                .array => try self.buildExplicitMoveFunctionVectorObjectArgJson(
                    allocator,
                    parameter.*,
                    object_id_value.array.items,
                ),
                else => return error.InvalidCli,
            };
        }
    }

    fn parseExplicitCoinBalanceArgJson(
        allocator: std.mem.Allocator,
        parameter: move_result.OwnedMoveParameterSummary,
    ) ?u64 {
        if (parameter.explicit_arg_json == null) return null;
        const lowering_kind = parameter.lowering_kind orelse return null;
        const parsed = std.json.parseFromSlice(std.json.Value, allocator, parameter.explicit_arg_json.?, .{}) catch return null;
        defer parsed.deinit();

        if (std.mem.eql(u8, lowering_kind, "u8") or
            std.mem.eql(u8, lowering_kind, "u16") or
            std.mem.eql(u8, lowering_kind, "u32") or
            std.mem.eql(u8, lowering_kind, "u64"))
        {
            return parseUnsignedJsonValueAs(u64, parsed.value) catch null;
        }
        if (std.mem.eql(u8, lowering_kind, "u128")) {
            const value = parseUnsignedJsonValueAs(u128, parsed.value) catch return null;
            if (value > std.math.maxInt(u64)) return null;
            return @intCast(value);
        }
        if (std.mem.eql(u8, lowering_kind, "u256")) {
            const value = parseUnsignedJsonValueAs(u256, parsed.value) catch return null;
            if (value > std.math.maxInt(u64)) return null;
            return @intCast(value);
        }
        return null;
    }

    fn buildAutoSelectedVectorArgJsonFromTokens(
        allocator: std.mem.Allocator,
        tokens: []const []const u8,
    ) !?[]u8 {
        if (tokens.len == 0) return null;

        var output = std.ArrayList(u8){};
        defer output.deinit(allocator);
        const writer = output.writer(allocator);
        try writer.writeAll("[");
        for (tokens, 0..) |token, index| {
            if (index != 0) try writer.writeAll(",");
            try writer.print("{f}", .{std.json.fmt(token, .{})});
        }
        try writer.writeAll("]");
        return try output.toOwnedSlice(allocator);
    }

    fn selectSmallestSufficientCoinCandidateToken(
        candidates: []const move_result.OwnedMoveObjectCandidate,
        min_balance: u64,
    ) ?[]const u8 {
        var selected_token: ?[]const u8 = null;
        var selected_balance: u64 = 0;
        for (candidates) |candidate| {
            const balance = candidate.balance orelse continue;
            if (balance < min_balance) continue;
            if (selected_token == null or balance < selected_balance) {
                selected_token = candidate.object_input_select_token;
                selected_balance = balance;
            }
        }
        return selected_token;
    }

    fn buildCoveringCoinVectorArgJson(
        allocator: std.mem.Allocator,
        candidates: []const move_result.OwnedMoveObjectCandidate,
        min_balance: u64,
    ) !?[]u8 {
        if (selectSmallestSufficientCoinCandidateToken(candidates, min_balance)) |token| {
            return try buildAutoSelectedVectorArgJsonFromTokens(allocator, &.{token});
        }

        var used = try allocator.alloc(bool, candidates.len);
        defer allocator.free(used);
        @memset(used, false);

        var selected_tokens = std.ArrayList([]const u8).empty;
        defer selected_tokens.deinit(allocator);

        var total_balance: u64 = 0;
        while (total_balance < min_balance) {
            var next_index: ?usize = null;
            var next_balance: u64 = 0;
            for (candidates, 0..) |candidate, index| {
                if (used[index]) continue;
                const balance = candidate.balance orelse continue;
                if (next_index == null or balance > next_balance) {
                    next_index = index;
                    next_balance = balance;
                }
            }
            const index = next_index orelse return null;
            used[index] = true;
            try selected_tokens.append(allocator, candidates[index].object_input_select_token);
            total_balance +|= next_balance;
        }

        return try buildAutoSelectedVectorArgJsonFromTokens(allocator, selected_tokens.items);
    }

    fn applyCoinSelectorMinBalanceHintsFromExplicitArgs(
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
        owner_address: ?[]const u8,
    ) !void {
        var previous_explicit_index: ?usize = null;
        for (parameters, 0..) |parameter, index| {
            if (parameter.omitted_from_explicit_args) continue;
            if (previous_explicit_index) |previous_index| {
                const min_balance = parseExplicitCoinBalanceArgJson(allocator, parameter) orelse {
                    previous_explicit_index = index;
                    continue;
                };
                const previous = &parameters[previous_index];

                if (previous.explicit_arg_json == null) {
                    if (coinTypeFromMoveSignature(previous.signature)) |coin_type| {
                        if (previous.coin_with_min_balance_select_token) |old_token| allocator.free(old_token);
                        previous.coin_with_min_balance_select_token = try buildCoinWithMinBalanceSelectToken(
                            allocator,
                            owner_address,
                            coin_type,
                            min_balance,
                        );
                        if (previous.placeholder_json) |old_placeholder| allocator.free(old_placeholder);
                        previous.placeholder_json = try buildAutoSelectedScalarArgJson(
                            allocator,
                            previous.coin_with_min_balance_select_token.?,
                        );
                    } else if (vectorElementTypeSignature(previous.signature)) |element_signature| {
                        if (coinTypeFromCoinStructType(element_signature)) |coin_type| {
                            if (previous.vector_item_coin_with_min_balance_select_token) |old_token| allocator.free(old_token);
                            previous.vector_item_coin_with_min_balance_select_token = try buildCoinWithMinBalanceSelectToken(
                                allocator,
                                owner_address,
                                coin_type,
                                min_balance,
                            );
                            if (previous.placeholder_json) |old_placeholder| allocator.free(old_placeholder);
                            previous.placeholder_json = try std.fmt.allocPrint(
                                allocator,
                                "[{f}]",
                                .{std.json.fmt(previous.vector_item_coin_with_min_balance_select_token.?, .{})},
                            );
                        }
                    }
                }
            }
            previous_explicit_index = index;
        }
    }

    fn replaceMoveParameterAutoSelectedArgJson(
        allocator: std.mem.Allocator,
        parameter: *move_result.OwnedMoveParameterSummary,
        value: ?[]u8,
    ) void {
        if (parameter.auto_selected_arg_json) |old_value| allocator.free(old_value);
        parameter.auto_selected_arg_json = value;
    }

    fn applyCoinCandidateSelectionHintsFromExplicitArgs(
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
    ) !void {
        var previous_explicit_index: ?usize = null;
        for (parameters, 0..) |parameter, index| {
            if (parameter.omitted_from_explicit_args) continue;
            if (previous_explicit_index) |previous_index| {
                const min_balance = parseExplicitCoinBalanceArgJson(allocator, parameter) orelse {
                    previous_explicit_index = index;
                    continue;
                };
                const previous = &parameters[previous_index];
                if (previous.explicit_arg_json != null) {
                    previous_explicit_index = index;
                    continue;
                }

                if (coinTypeFromMoveSignature(previous.signature) != null) {
                    if (previous.owned_object_candidates) |candidates| {
                        const selected_value = if (selectSmallestSufficientCoinCandidateToken(candidates, min_balance)) |token|
                            try buildAutoSelectedScalarArgJson(allocator, token)
                        else
                            null;
                        replaceMoveParameterAutoSelectedArgJson(allocator, previous, selected_value);
                    }
                } else if (vectorElementTypeSignature(previous.signature)) |element_signature| {
                    if (coinTypeFromCoinStructType(element_signature) != null) {
                        if (previous.vector_item_owned_object_candidates) |candidates| {
                            const selected_value = try buildCoveringCoinVectorArgJson(
                                allocator,
                                candidates,
                                min_balance,
                            );
                            replaceMoveParameterAutoSelectedArgJson(allocator, previous, selected_value);
                        }
                    }
                }
            }
            previous_explicit_index = index;
        }
    }

    fn populateMoveParameterAutoSelectedArgJson(
        allocator: std.mem.Allocator,
        parameter: *move_result.OwnedMoveParameterSummary,
    ) !void {
        if (parameter.omitted_from_explicit_args) return;
        if (parameter.auto_selected_arg_json != null) return;

        if (parameter.vector_item_owned_object_candidates) |candidates| {
            parameter.auto_selected_arg_json = try buildAutoSelectedVectorArgJson(allocator, candidates);
            if (parameter.auto_selected_arg_json != null) return;
        }

        if (parameter.shared_object_candidates) |candidates| {
            if (candidates.len == 1) {
                const token = if (isMoveMutableReferenceSignature(parameter.signature))
                    candidates[0].mutable_shared_object_input_select_token
                else
                    candidates[0].shared_object_input_select_token;
                parameter.auto_selected_arg_json = try buildAutoSelectedScalarArgJson(allocator, token);
                return;
            }
        }

        if (parameter.owned_object_candidates) |candidates| {
            if (candidates.len == 1) {
                parameter.auto_selected_arg_json = try buildAutoSelectedScalarArgJson(
                    allocator,
                    candidates[0].object_input_select_token,
                );
            } else if (coinTypeFromMoveSignature(parameter.signature) != null) {
                var selected_token: ?[]const u8 = null;
                var selected_balance: u64 = 0;
                for (candidates) |candidate| {
                    const balance = candidate.balance orelse continue;
                    if (selected_token == null or balance > selected_balance) {
                        selected_token = candidate.object_input_select_token;
                        selected_balance = balance;
                    }
                }
                if (selected_token) |token| {
                    parameter.auto_selected_arg_json = try buildAutoSelectedScalarArgJson(allocator, token);
                }
            }
        }
    }

    fn resolvedMoveFunctionTypeArgsTemplateJson(
        allocator: std.mem.Allocator,
        type_parameter_count: usize,
        concrete_type_arguments_json: ?[]const u8,
    ) ![]u8 {
        if (concrete_type_arguments_json) |value| return try allocator.dupe(u8, value);
        return try buildMoveFunctionTypeArgsTemplateJson(allocator, type_parameter_count);
    }

    fn buildMoveFunctionCommandTemplateJson(
        allocator: std.mem.Allocator,
        summary: move_result.OwnedMoveFunctionSummary,
        type_args_json: []const u8,
        args_json: []const u8,
    ) ![]u8 {
        const package_id = summary.package_id orelse return error.InvalidResponse;
        const module_name = summary.module_name orelse return error.InvalidResponse;
        const function_name = summary.function_name orelse return error.InvalidResponse;

        var output = std.ArrayList(u8){};
        defer output.deinit(allocator);

        try output.writer(allocator).print(
            "{{\"kind\":\"MoveCall\",\"package\":{f},\"module\":{f},\"function\":{f},\"typeArguments\":{s},\"arguments\":{s}}}",
            .{
                std.json.fmt(package_id, .{}),
                std.json.fmt(module_name, .{}),
                std.json.fmt(function_name, .{}),
                type_args_json,
                args_json,
            },
        );
        return output.toOwnedSlice(allocator);
    }

    fn buildMoveFunctionCommandsTemplateJson(
        allocator: std.mem.Allocator,
        move_call_command_json: []const u8,
    ) ![]u8 {
        return try std.fmt.allocPrint(allocator, "[{s}]", .{move_call_command_json});
    }

