    fn buildMoveFunctionTxDryRunArgv(
        allocator: std.mem.Allocator,
        summary: move_result.OwnedMoveFunctionSummary,
        type_args_json: []const u8,
        args_json: []const u8,
        sender: ?[]const u8,
    ) ![][]u8 {
        const package_id = summary.package_id orelse return error.InvalidResponse;
        const module_name = summary.module_name orelse return error.InvalidResponse;
        const function_name = summary.function_name orelse return error.InvalidResponse;

        const argv = try allocator.alloc([]u8, 19);
        errdefer allocator.free(argv);

        argv[0] = try allocator.dupe(u8, "tx");
        errdefer allocator.free(argv[0]);
        argv[1] = try allocator.dupe(u8, "dry-run");
        errdefer allocator.free(argv[1]);
        argv[2] = try allocator.dupe(u8, "--package");
        errdefer allocator.free(argv[2]);
        argv[3] = try allocator.dupe(u8, package_id);
        errdefer allocator.free(argv[3]);
        argv[4] = try allocator.dupe(u8, "--module");
        errdefer allocator.free(argv[4]);
        argv[5] = try allocator.dupe(u8, module_name);
        errdefer allocator.free(argv[5]);
        argv[6] = try allocator.dupe(u8, "--function");
        errdefer allocator.free(argv[6]);
        argv[7] = try allocator.dupe(u8, function_name);
        errdefer allocator.free(argv[7]);
        argv[8] = try allocator.dupe(u8, "--type-args");
        errdefer allocator.free(argv[8]);
        argv[9] = try allocator.dupe(u8, type_args_json);
        errdefer allocator.free(argv[9]);
        argv[10] = try allocator.dupe(u8, "--args");
        errdefer allocator.free(argv[10]);
        argv[11] = try allocator.dupe(u8, args_json);
        errdefer allocator.free(argv[11]);
        argv[12] = try allocator.dupe(u8, "--sender");
        errdefer allocator.free(argv[12]);
        argv[13] = try allocator.dupe(u8, sender orelse "0x<sender>");
        errdefer allocator.free(argv[13]);
        argv[14] = try allocator.dupe(u8, "--gas-budget");
        errdefer allocator.free(argv[14]);
        argv[15] = try allocator.dupe(u8, "100000000");
        errdefer allocator.free(argv[15]);
        argv[16] = try allocator.dupe(u8, "--gas-price");
        errdefer allocator.free(argv[16]);
        argv[17] = try allocator.dupe(u8, "1000");
        errdefer allocator.free(argv[17]);
        argv[18] = try allocator.dupe(u8, "--summarize");
        errdefer allocator.free(argv[18]);

        return argv;
    }

    fn buildMoveFunctionTxSendFromKeystoreArgv(
        allocator: std.mem.Allocator,
        summary: move_result.OwnedMoveFunctionSummary,
        type_args_json: []const u8,
        args_json: []const u8,
        signer_selector: ?[]const u8,
        sender: ?[]const u8,
    ) ![][]u8 {
        const package_id = summary.package_id orelse return error.InvalidResponse;
        const module_name = summary.module_name orelse return error.InvalidResponse;
        const function_name = summary.function_name orelse return error.InvalidResponse;

        const argv = try allocator.alloc([]u8, 20);
        errdefer allocator.free(argv);

        argv[0] = try allocator.dupe(u8, "tx");
        errdefer allocator.free(argv[0]);
        argv[1] = try allocator.dupe(u8, "send");
        errdefer allocator.free(argv[1]);
        argv[2] = try allocator.dupe(u8, "--package");
        errdefer allocator.free(argv[2]);
        argv[3] = try allocator.dupe(u8, package_id);
        errdefer allocator.free(argv[3]);
        argv[4] = try allocator.dupe(u8, "--module");
        errdefer allocator.free(argv[4]);
        argv[5] = try allocator.dupe(u8, module_name);
        errdefer allocator.free(argv[5]);
        argv[6] = try allocator.dupe(u8, "--function");
        errdefer allocator.free(argv[6]);
        argv[7] = try allocator.dupe(u8, function_name);
        errdefer allocator.free(argv[7]);
        argv[8] = try allocator.dupe(u8, "--type-args");
        errdefer allocator.free(argv[8]);
        argv[9] = try allocator.dupe(u8, type_args_json);
        errdefer allocator.free(argv[9]);
        argv[10] = try allocator.dupe(u8, "--args");
        errdefer allocator.free(argv[10]);
        argv[11] = try allocator.dupe(u8, args_json);
        errdefer allocator.free(argv[11]);
        argv[12] = try allocator.dupe(u8, "--from-keystore");
        errdefer allocator.free(argv[12]);
        argv[13] = try allocator.dupe(u8, "--signer");
        errdefer allocator.free(argv[13]);
        argv[14] = try allocator.dupe(u8, signer_selector orelse sender orelse "<alias-or-address>");
        errdefer allocator.free(argv[14]);
        argv[15] = try allocator.dupe(u8, "--gas-budget");
        errdefer allocator.free(argv[15]);
        argv[16] = try allocator.dupe(u8, "100000000");
        errdefer allocator.free(argv[16]);
        argv[17] = try allocator.dupe(u8, "--auto-gas-payment");
        errdefer allocator.free(argv[17]);
        argv[18] = try allocator.dupe(u8, "--wait");
        errdefer allocator.free(argv[18]);
        argv[19] = try allocator.dupe(u8, "--summarize");
        errdefer allocator.free(argv[19]);

        return argv;
    }

    fn applyMoveFunctionTypeArgumentsToSummary(
        allocator: std.mem.Allocator,
        summary: *move_result.OwnedMoveFunctionSummary,
        parameters_value: std.json.Value,
        returns_value: std.json.Value,
        type_arguments_json: []const u8,
    ) ![]u8 {
        const parsed_type_arguments = try std.json.parseFromSlice(std.json.Value, allocator, type_arguments_json, .{});
        defer parsed_type_arguments.deinit();
        if (parsed_type_arguments.value != .array) return error.InvalidCli;
        const raw_type_arguments = parsed_type_arguments.value.array.items;
        if (raw_type_arguments.len != summary.type_parameters.len) return error.InvalidCli;

        const canonical_type_arguments_json = try canonicalMoveTypeArgumentsJson(allocator, raw_type_arguments);
        errdefer allocator.free(canonical_type_arguments_json);

        for (parameters_value.array.items, 0..) |parameter, index| {
            const resolved_parameter_json = try substituteNormalizedMoveTypeJson(allocator, parameter, raw_type_arguments);
            defer allocator.free(resolved_parameter_json);
            const resolved_parameter_parsed = try std.json.parseFromSlice(std.json.Value, allocator, resolved_parameter_json, .{});
            defer resolved_parameter_parsed.deinit();

            allocator.free(summary.parameters[index].signature);
            summary.parameters[index].signature = try move_result.moveTypeText(allocator, resolved_parameter_parsed.value);
            const classified = try classifyNormalizedMoveType(allocator, resolved_parameter_parsed.value);
            summary.parameters[index].lowering_kind = if (classified) |kind|
                @tagName(kind)
            else
                "runtime";
        }

        for (returns_value.array.items, 0..) |item, index| {
            const resolved_return_json = try substituteNormalizedMoveTypeJson(allocator, item, raw_type_arguments);
            defer allocator.free(resolved_return_json);
            const resolved_return_parsed = try std.json.parseFromSlice(std.json.Value, allocator, resolved_return_json, .{});
            defer resolved_return_parsed.deinit();

            allocator.free(summary.returns[index].signature);
            summary.returns[index].signature = try move_result.moveTypeText(allocator, resolved_return_parsed.value);
        }

        summary.applied_type_args_json = try allocator.dupe(u8, canonical_type_arguments_json);
        return canonical_type_arguments_json;
    }

    fn populateMoveFunctionCallTemplate(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        summary: *move_result.OwnedMoveFunctionSummary,
        parameter_allows_owned_discovery: []const bool,
        concrete_type_arguments_json: ?[]const u8,
        arguments_json: ?[]const u8,
        indexed_arguments_json: ?[]const u8,
        indexed_object_arguments_json: ?[]const u8,
        owner_address: ?[]const u8,
        signer_selector: ?[]const u8,
    ) !void {
        for (summary.parameters, 0..) |*parameter, index| {
            parameter.placeholder_json = try placeholderJsonForMoveParameter(allocator, parameter.*, index);
            parameter.omitted_from_explicit_args = parameter.placeholder_json == null;

            if (parameter.omitted_from_explicit_args) continue;
            const lowering_kind = parameter.lowering_kind orelse continue;
            if (std.mem.eql(u8, lowering_kind, "vector")) {
                const item_struct_type = concreteVectorObjectStructTypeFromSignature(parameter.signature) orelse continue;
                const object_id_placeholder = try std.fmt.allocPrint(
                    allocator,
                    "0x<arg{d}-item0-object-id>",
                    .{index},
                );
                defer allocator.free(object_id_placeholder);

                parameter.vector_item_object_get_argv = try buildObjectGetArgv(allocator, object_id_placeholder);
                parameter.vector_item_imm_or_owned_object_input_select_token = try buildObjectInputSelectToken(
                    allocator,
                    object_id_placeholder,
                    .imm_or_owned,
                    false,
                );
                parameter.vector_item_owned_object_select_token = try buildOwnedObjectSelectToken(
                    allocator,
                    owner_address,
                    item_struct_type,
                );
                parameter.vector_item_owned_object_query_argv = if (coinTypeFromCoinStructType(item_struct_type)) |coin_type| blk: {
                    parameter.vector_item_coin_with_min_balance_select_token = try buildCoinWithMinBalanceSelectToken(
                        allocator,
                        owner_address,
                        coin_type,
                        1,
                    );
                    allocator.free(parameter.placeholder_json.?);
                    parameter.placeholder_json = try std.fmt.allocPrint(
                        allocator,
                        "[{f}]",
                        .{std.json.fmt(parameter.vector_item_coin_with_min_balance_select_token.?, .{})},
                    );
                    break :blk try buildCoinQueryArgv(
                        allocator,
                        owner_address,
                        coin_type,
                    );
                } else try buildOwnedObjectQueryArgv(
                    allocator,
                    owner_address,
                    item_struct_type,
                );
                if (owner_address) |owner| {
                    parameter.vector_item_owned_object_candidates = try self.discoverOwnedObjectCandidates(
                        allocator,
                        owner,
                        item_struct_type,
                    );
                }
                continue;
            }
            if (!std.mem.eql(u8, lowering_kind, "object")) continue;
            if (object_preset.inferKindFromTypeSignature(parameter.signature)) |preset_kind| {
                parameter.object_get_argv = try buildObjectGetArgv(
                    allocator,
                    object_preset.canonicalName(preset_kind),
                );
            } else {
                const object_id_placeholder = try std.fmt.allocPrint(
                    allocator,
                    "0x<arg{d}-object-id>",
                    .{index},
                );
                defer allocator.free(object_id_placeholder);

                parameter.object_get_argv = try buildObjectGetArgv(allocator, object_id_placeholder);
                parameter.imm_or_owned_object_input_select_token = try buildObjectInputSelectToken(
                    allocator,
                    object_id_placeholder,
                    .imm_or_owned,
                    false,
                );
                if (isMoveReferenceSignature(parameter.signature)) {
                    parameter.shared_object_input_select_token = try buildObjectInputSelectToken(
                        allocator,
                        object_id_placeholder,
                        .shared,
                        isMoveMutableReferenceSignature(parameter.signature),
                    );
                    if (concreteObjectStructTypeFromSignature(parameter.signature) == null) {
                        if (summary.package_id) |event_package_id| {
                            const event_module_name = summary.module_name orelse continue;
                            parameter.shared_object_event_query_argv = try buildEventQueryArgv(
                                allocator,
                                event_package_id,
                                event_module_name,
                            );
                            if (!containsMoveTypeParameterText(trimMoveReferenceSignature(parameter.signature))) {
                                parameter.shared_object_candidates = try self.discoverSharedObjectCandidatesFromModuleEvents(
                                    allocator,
                                    event_package_id,
                                    event_module_name,
                                    parameter.signature,
                                );
                            }
                        } else if (moveStructPackageAndModule(parameter.signature)) |package_and_module| {
                            parameter.shared_object_event_query_argv = try buildEventQueryArgv(
                                allocator,
                                package_and_module.package,
                                package_and_module.module,
                            );
                            if (!containsMoveTypeParameterText(trimMoveReferenceSignature(parameter.signature))) {
                                parameter.shared_object_candidates = try self.discoverSharedObjectCandidatesFromModuleEvents(
                                    allocator,
                                    package_and_module.package,
                                    package_and_module.module,
                                    parameter.signature,
                                );
                            }
                        }
                    }
                } else {
                    parameter.receiving_object_input_select_token = try buildObjectInputSelectToken(
                        allocator,
                        object_id_placeholder,
                        .receiving,
                        false,
                    );
                }
            }

            if (!parameter_allows_owned_discovery[index]) continue;
            if (object_preset.inferKindFromTypeSignature(parameter.signature) != null) continue;
            const struct_type = concreteObjectStructTypeFromSignature(parameter.signature) orelse blk: {
                if (coinTypeFromMoveSignature(parameter.signature) == null) break :blk null;
                break :blk trimMoveReferenceSignature(parameter.signature);
            } orelse continue;
            parameter.owned_object_select_token = try buildOwnedObjectSelectToken(allocator, owner_address, struct_type);
            parameter.owned_object_query_argv = if (coinTypeFromCoinStructType(struct_type)) |coin_type| blk: {
                parameter.coin_with_min_balance_select_token = try buildCoinWithMinBalanceSelectToken(
                    allocator,
                    owner_address,
                    coin_type,
                    1,
                );
                allocator.free(parameter.placeholder_json.?);
                parameter.placeholder_json = try buildAutoSelectedScalarArgJson(
                    allocator,
                    parameter.coin_with_min_balance_select_token.?,
                );
                break :blk try buildCoinQueryArgv(allocator, owner_address, coin_type);
            } else try buildOwnedObjectQueryArgv(allocator, owner_address, struct_type);
            if (owner_address) |owner| {
                parameter.owned_object_candidates = try self.discoverOwnedObjectCandidates(
                    allocator,
                    owner,
                    struct_type,
                );
            }

            try populateMoveParameterAutoSelectedArgJson(allocator, parameter);
            continue;
        }

        for (summary.parameters) |*parameter| {
            try populateMoveParameterAutoSelectedArgJson(allocator, parameter);
        }

        if (arguments_json) |value| {
            try applyExplicitMoveFunctionArgsToParameters(allocator, summary.parameters, value);
        }
        if (indexed_arguments_json) |value| {
            try applyExplicitIndexedMoveFunctionArgsToParameters(allocator, summary.parameters, value);
        }
        if (indexed_object_arguments_json) |value| {
            try self.applyExplicitIndexedObjectMoveFunctionArgsToParameters(allocator, summary.parameters, value);
        }
        if (arguments_json != null or indexed_arguments_json != null or indexed_object_arguments_json != null) {
            try applyCoinSelectorMinBalanceHintsFromExplicitArgs(
                allocator,
                summary.parameters,
                owner_address,
            );
            try applyCoinCandidateSelectionHintsFromExplicitArgs(
                allocator,
                summary.parameters,
            );
        }

        const type_args_json = try resolvedMoveFunctionTypeArgsTemplateJson(
            allocator,
            summary.type_parameters.len,
            concrete_type_arguments_json,
        );
        errdefer allocator.free(type_args_json);
        const args_json = try buildMoveFunctionArgsTemplateJson(allocator, summary.parameters);
        errdefer allocator.free(args_json);
        const preferred_args_json = try buildMoveFunctionArgsJson(allocator, summary.parameters, true);
        errdefer allocator.free(preferred_args_json);
        const move_call_command_json = try buildMoveFunctionCommandTemplateJson(
            allocator,
            summary.*,
            type_args_json,
            args_json,
        );
        errdefer allocator.free(move_call_command_json);
        const commands_json = try buildMoveFunctionCommandsTemplateJson(allocator, move_call_command_json);
        errdefer allocator.free(commands_json);
        const tx_dry_run_request_json = try buildMoveFunctionTxDryRunRequestJson(
            allocator,
            commands_json,
            owner_address,
        );
        errdefer allocator.free(tx_dry_run_request_json);
        const tx_send_from_keystore_request_json = try buildMoveFunctionTxSendFromKeystoreRequestJson(
            allocator,
            commands_json,
            signer_selector,
            owner_address,
        );
        errdefer allocator.free(tx_send_from_keystore_request_json);
        const tx_dry_run_argv = try buildMoveFunctionTxDryRunArgv(
            allocator,
            summary.*,
            type_args_json,
            args_json,
            owner_address,
        );
        errdefer {
            for (tx_dry_run_argv) |value| allocator.free(value);
            allocator.free(tx_dry_run_argv);
        }
        const tx_send_from_keystore_argv = try buildMoveFunctionTxSendFromKeystoreArgv(
            allocator,
            summary.*,
            type_args_json,
            args_json,
            signer_selector,
            owner_address,
        );
        errdefer {
            for (tx_send_from_keystore_argv) |value| allocator.free(value);
            allocator.free(tx_send_from_keystore_argv);
        }

        const has_preferred_args = !std.mem.eql(u8, preferred_args_json, args_json);
        const preferred_move_call_command_json = if (has_preferred_args)
            try buildMoveFunctionCommandTemplateJson(
                allocator,
                summary.*,
                type_args_json,
                preferred_args_json,
            )
        else
            null;
        errdefer if (preferred_move_call_command_json) |value| allocator.free(value);
        const preferred_commands_json = if (preferred_move_call_command_json) |value|
            try buildMoveFunctionCommandsTemplateJson(allocator, value)
        else
            null;
        if (preferred_move_call_command_json) |value| allocator.free(value);
        errdefer if (preferred_commands_json) |value| allocator.free(value);
        const preferred_tx_dry_run_request_json = if (preferred_commands_json) |value|
            try buildMoveFunctionTxDryRunRequestJson(allocator, value, owner_address)
        else
            null;
        errdefer if (preferred_tx_dry_run_request_json) |value| allocator.free(value);
        const preferred_tx_send_from_keystore_request_json = if (preferred_commands_json) |value|
            try buildMoveFunctionTxSendFromKeystoreRequestJson(
                allocator,
                value,
                signer_selector,
                owner_address,
            )
        else
            null;
        errdefer if (preferred_tx_send_from_keystore_request_json) |value| allocator.free(value);
        const preferred_tx_dry_run_argv = if (has_preferred_args)
            try buildMoveFunctionTxDryRunArgv(
                allocator,
                summary.*,
                type_args_json,
                preferred_args_json,
                owner_address,
            )
        else
            null;
        errdefer if (preferred_tx_dry_run_argv) |argv| {
            for (argv) |value| allocator.free(value);
            allocator.free(argv);
        };
        const preferred_tx_send_from_keystore_argv = if (has_preferred_args)
            try buildMoveFunctionTxSendFromKeystoreArgv(
                allocator,
                summary.*,
                type_args_json,
                preferred_args_json,
                signer_selector,
                owner_address,
            )
        else
            null;
        errdefer if (preferred_tx_send_from_keystore_argv) |argv| {
            for (argv) |value| allocator.free(value);
            allocator.free(argv);
        };

        summary.call_template = .{
            .type_args_json = type_args_json,
            .args_json = args_json,
            .preferred_args_json = if (!has_preferred_args) blk: {
                allocator.free(preferred_args_json);
                break :blk null;
            } else preferred_args_json,
            .move_call_command_json = move_call_command_json,
            .commands_json = commands_json,
            .preferred_commands_json = preferred_commands_json,
            .tx_dry_run_request_json = tx_dry_run_request_json,
            .preferred_tx_dry_run_request_json = preferred_tx_dry_run_request_json,
            .tx_dry_run_argv = tx_dry_run_argv,
            .preferred_tx_dry_run_argv = preferred_tx_dry_run_argv,
            .tx_send_from_keystore_request_json = tx_send_from_keystore_request_json,
            .preferred_tx_send_from_keystore_request_json = preferred_tx_send_from_keystore_request_json,
            .tx_send_from_keystore_argv = tx_send_from_keystore_argv,
            .preferred_tx_send_from_keystore_argv = preferred_tx_send_from_keystore_argv,
        };
    }

    pub fn summarizeMoveFunctionResponse(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        package_id: []const u8,
        module: []const u8,
        function_name: []const u8,
        response_json: []const u8,
        type_arguments_json: ?[]const u8,
        arguments_json: ?[]const u8,
        indexed_arguments_json: ?[]const u8,
        indexed_object_arguments_json: ?[]const u8,
        owner_address: ?[]const u8,
        signer_selector: ?[]const u8,
    ) !move_result.OwnedMoveFunctionSummary {
        var summary = try move_result.extractMoveFunctionSummary(
            allocator,
            response_json,
            package_id,
            module,
            function_name,
        );
        errdefer summary.deinit(allocator);

        const parsed = try std.json.parseFromSlice(std.json.Value, allocator, response_json, .{});
        defer parsed.deinit();

        if (parsed.value != .object) return error.InvalidResponse;
        const result = parsed.value.object.get("result") orelse return error.InvalidResponse;
        if (result != .object) return error.InvalidResponse;
        const parameters = result.object.get("parameters") orelse return error.InvalidResponse;
        const returns = result.object.get("return") orelse result.object.get("returns") orelse return error.InvalidResponse;
        if (parameters != .array) return error.InvalidResponse;
        if (returns != .array) return error.InvalidResponse;
        if (parameters.array.items.len != summary.parameters.len) return error.InvalidResponse;

        const parameter_allows_owned_discovery = try allocator.alloc(bool, parameters.array.items.len);
        defer allocator.free(parameter_allows_owned_discovery);
        for (parameters.array.items, 0..) |item, index| {
            parameter_allows_owned_discovery[index] = !normalizedMoveTypeContainsTypeParameter(item);
        }

        const resolved_type_arguments_json = if (type_arguments_json) |raw_type_arguments_json|
            try applyMoveFunctionTypeArgumentsToSummary(
                allocator,
                &summary,
                parameters,
                returns,
                raw_type_arguments_json,
            )
        else blk: {
            for (parameters.array.items, 0..) |item, index| {
                const classified = try classifyNormalizedMoveType(allocator, item);
                summary.parameters[index].lowering_kind = if (classified) |kind|
                    @tagName(kind)
                else
                    "runtime";
            }
            break :blk null;
        };
        defer if (resolved_type_arguments_json) |value| allocator.free(value);

        for (summary.parameters, 0..) |parameter, index| {
            if (coinTypeFromMoveSignature(parameter.signature) != null) {
                parameter_allows_owned_discovery[index] = true;
            }
        }

        try populateMoveFunctionCallTemplate(
            self,
            allocator,
            &summary,
            parameter_allows_owned_discovery,
            resolved_type_arguments_json,
            arguments_json,
            indexed_arguments_json,
            indexed_object_arguments_json,
            owner_address,
            signer_selector,
        );

        return summary;
    }

    pub fn summarizeMoveModuleResponse(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        package_id: []const u8,
        module: []const u8,
        response_json: []const u8,
    ) !move_result.OwnedMoveModuleSummary {
        _ = self;
        return try move_result.extractMoveModuleSummary(
            allocator,
            response_json,
            package_id,
            module,
        );
    }

    pub fn summarizeMovePackageResponse(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        package_id: []const u8,
        response_json: []const u8,
    ) !move_result.OwnedMovePackageSummary {
        _ = self;
        return try move_result.extractMovePackageSummary(allocator, response_json, package_id);
    }

    pub fn getMoveCallUserParameterKinds(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        package_id: []const u8,
        module: []const u8,
        function_name: []const u8,
        raw_type_arguments_json: ?[]const u8,
    ) ![]LocalMoveCallParameterKind {
        const response = try self.getNormalizedMoveFunction(allocator, package_id, module, function_name);
        defer allocator.free(response);

        const parsed = try std.json.parseFromSlice(std.json.Value, allocator, response, .{});
        defer parsed.deinit();

        if (parsed.value != .object) return error.InvalidResponse;
        const result = parsed.value.object.get("result") orelse return error.InvalidResponse;
        if (result != .object) return error.InvalidResponse;
        const parameters = result.object.get("parameters") orelse return error.InvalidResponse;
        if (parameters != .array) return error.InvalidResponse;

        var parsed_type_arguments: ?std.json.Parsed(std.json.Value) = null;
        defer if (parsed_type_arguments) |*value| value.deinit();
        const raw_type_arguments: []const std.json.Value = if (raw_type_arguments_json) |type_arguments_json| blk: {
            parsed_type_arguments = try std.json.parseFromSlice(std.json.Value, allocator, type_arguments_json, .{});
            if (parsed_type_arguments.?.value != .array) return error.InvalidCli;
            break :blk parsed_type_arguments.?.value.array.items;
        } else &.{};

        var kinds = std.ArrayList(LocalMoveCallParameterKind){};
        defer kinds.deinit(allocator);
        for (parameters.array.items) |parameter| {
            const resolved_parameter_json = if (raw_type_arguments_json != null)
                try substituteNormalizedMoveTypeJson(allocator, parameter, raw_type_arguments)
            else
                try canonicalNormalizedMoveTypeJson(allocator, parameter);
            defer allocator.free(resolved_parameter_json);

            const resolved_parameter_parsed = try std.json.parseFromSlice(std.json.Value, allocator, resolved_parameter_json, .{});
            defer resolved_parameter_parsed.deinit();
            const classified = try classifyNormalizedMoveType(allocator, resolved_parameter_parsed.value);
            if (classified == null) continue;
            try kinds.append(allocator, classified.?);
        }

        return try kinds.toOwnedSlice(allocator);
    }

    pub fn commandSourceSupportsLocalProgrammableTransactionBuilder(
        allocator: std.mem.Allocator,
        source: tx_builder.CommandSource,
    ) !bool {
        const commands_json = try tx_builder.resolveCommands(allocator, source);
        defer allocator.free(commands_json);

        const parsed = std.json.parseFromSlice(std.json.Value, allocator, commands_json, .{}) catch |err| switch (err) {
            error.OutOfMemory => return error.OutOfMemory,
            else => return false,
        };
        defer parsed.deinit();

        if (parsed.value != .array) return false;
        for (parsed.value.array.items) |command| {
            if (command != .object) return false;
            const kind = command.object.get("kind") orelse return false;
            if (kind != .string) return false;
            if (!std.mem.eql(u8, kind.string, "MoveCall") and
                !std.mem.eql(u8, kind.string, "TransferObjects") and
                !std.mem.eql(u8, kind.string, "SplitCoins") and
                !std.mem.eql(u8, kind.string, "MergeCoins") and
                !std.mem.eql(u8, kind.string, "MakeMoveVec") and
                !std.mem.eql(u8, kind.string, "Publish") and
                !std.mem.eql(u8, kind.string, "Upgrade"))
            {
                return false;
            }
        }
        return true;
    }

    pub fn ownLocalProgrammableTransactionPartsFromCommandSource(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        source: tx_builder.CommandSource,
        sender: []const u8,
        gas_payment_json: []const u8,
        gas_price: u64,
        gas_budget: u64,
        expiration_json: ?[]const u8,
    ) !OwnedLocalProgrammableTransactionParts {
        const commands_json = try tx_builder.resolveCommands(allocator, source);
        defer allocator.free(commands_json);

        const parsed = try std.json.parseFromSlice(std.json.Value, allocator, commands_json, .{});
        defer parsed.deinit();
        if (parsed.value != .array) return error.InvalidCli;

        const LoweringContext = struct {
            rpc: *SuiRpcClient,
            allocator: std.mem.Allocator,
            inputs: std.ArrayListUnmanaged([]u8) = .{},
            commands: std.ArrayListUnmanaged([]u8) = .{},

            fn deinit(ctx: *@This()) void {
                for (ctx.inputs.items) |item| ctx.allocator.free(item);
                for (ctx.commands.items) |item| ctx.allocator.free(item);
                ctx.inputs.deinit(ctx.allocator);
                ctx.commands.deinit(ctx.allocator);
            }

            fn appendInput(ctx: *@This(), input_json: []u8) !u16 {
                try ctx.inputs.append(ctx.allocator, input_json);
                const index = ctx.inputs.items.len - 1;
                if (index > std.math.maxInt(u16)) return error.InvalidCli;
                return @intCast(index);
            }

            fn buildInputRefJson(ctx: *@This(), input_index: u16) ![]u8 {
                return try std.fmt.allocPrint(ctx.allocator, "{{\"Input\":{}}}", .{input_index});
            }

            fn buildResultRefJson(ctx: *@This(), command_index: u16) ![]u8 {
                return try std.fmt.allocPrint(ctx.allocator, "{{\"Result\":{}}}", .{command_index});
            }

            fn appendCommand(ctx: *@This(), command_json: []u8) !u16 {
                try ctx.commands.append(ctx.allocator, command_json);
                const index = ctx.commands.items.len - 1;
                if (index > std.math.maxInt(u16)) return error.InvalidCli;
                return @intCast(index);
            }

            fn normalizePtbRefOrAddExplicitInput(
                ctx: *@This(),
                value: std.json.Value,
                allow_existing_input: bool,
            ) ![]u8 {
                switch (value) {
                    .string => |string_value| {
                        if (std.mem.eql(u8, string_value, "GasCoin")) {
                            return try ctx.allocator.dupe(u8, "\"GasCoin\"");
                        }
                        return error.InvalidCli;
                    },
                    .object => |object| {
                        if (object.get("Result") != null or object.get("NestedResult") != null) {
                            return try stringifyJsonValueAlloc(ctx.allocator, value);
                        }
                        if (object.get("Input") != null) {
                            if (!allow_existing_input) return error.InvalidCli;
                            return try stringifyJsonValueAlloc(ctx.allocator, value);
                        }
                        if (object.get("Pure") != null or object.get("Object") != null) {
                            const input_json = try stringifyJsonValueAlloc(ctx.allocator, value);
                            errdefer ctx.allocator.free(input_json);
                            const input_index = try ctx.appendInput(input_json);
                            return try ctx.buildInputRefJson(input_index);
                        }
                        return error.InvalidCli;
                    },
                    else => return error.InvalidCli,
                }
            }

            fn lowerObjectArgument(
                ctx: *@This(),
                value: std.json.Value,
            ) ![]u8 {
                switch (value) {
                    .string => |object_id| {
                        if (std.mem.eql(u8, object_id, "GasCoin")) {
                            return try ctx.allocator.dupe(u8, "\"GasCoin\"");
                        }
                        const input_json = try ctx.rpc.resolveImmOrOwnedObjectInputJson(ctx.allocator, object_id);
                        errdefer ctx.allocator.free(input_json);
                        const input_index = try ctx.appendInput(input_json);
                        return try ctx.buildInputRefJson(input_index);
                    },
                    .object => return try ctx.normalizePtbRefOrAddExplicitInput(value, false),
                    else => return error.InvalidCli,
                }
            }

            fn lowerMoveCallArgument(
                ctx: *@This(),
                value: std.json.Value,
            ) ![]u8 {
                return try ctx.normalizePtbRefOrAddExplicitInput(value, false);
            }

            fn lowerMoveCallArgumentForKind(
                ctx: *@This(),
                value: std.json.Value,
                kind: LocalMoveCallParameterKind,
            ) ![]u8 {
                switch (kind) {
                    .object => return try ctx.lowerObjectArgument(value),
                    .address, .signer => return switch (value) {
                        .string => |address| blk: {
                            const input_json = try buildPureAddressInputJson(ctx.allocator, address);
                            errdefer ctx.allocator.free(input_json);
                            const input_index = try ctx.appendInput(input_json);
                            break :blk try ctx.buildInputRefJson(input_index);
                        },
                        .object => |object| blk: {
                            if (object.get("Object") != null) return error.InvalidCli;
                            break :blk try ctx.normalizePtbRefOrAddExplicitInput(value, false);
                        },
                        else => error.InvalidCli,
                    },
                    .boolean => return switch (value) {
                        .bool => |boolean| blk: {
                            const input_json = try buildPureBoolInputJson(ctx.allocator, boolean);
                            errdefer ctx.allocator.free(input_json);
                            const input_index = try ctx.appendInput(input_json);
                            break :blk try ctx.buildInputRefJson(input_index);
                        },
                        .object => |object| blk: {
                            if (object.get("Object") != null) return error.InvalidCli;
                            break :blk try ctx.normalizePtbRefOrAddExplicitInput(value, false);
                        },
                        else => error.InvalidCli,
                    },
                    .u8 => return switch (value) {
                        .integer, .number_string, .string => blk: {
                            const input_json = try buildPureUnsignedInputJson(u8, ctx.allocator, try parseUnsignedJsonValueAs(u8, value));
                            errdefer ctx.allocator.free(input_json);
                            const input_index = try ctx.appendInput(input_json);
                            break :blk try ctx.buildInputRefJson(input_index);
                        },
                        .object => |object| blk: {
                            if (object.get("Object") != null) return error.InvalidCli;
                            break :blk try ctx.normalizePtbRefOrAddExplicitInput(value, false);
                        },
                        else => error.InvalidCli,
                    },
                    .u16 => return switch (value) {
                        .integer, .number_string, .string => blk: {
                            const input_json = try buildPureUnsignedInputJson(u16, ctx.allocator, try parseUnsignedJsonValueAs(u16, value));
                            errdefer ctx.allocator.free(input_json);
                            const input_index = try ctx.appendInput(input_json);
                            break :blk try ctx.buildInputRefJson(input_index);
                        },
                        .object => |object| blk: {
                            if (object.get("Object") != null) return error.InvalidCli;
                            break :blk try ctx.normalizePtbRefOrAddExplicitInput(value, false);
                        },
                        else => error.InvalidCli,
                    },
                    .u32 => return switch (value) {
                        .integer, .number_string, .string => blk: {
                            const input_json = try buildPureUnsignedInputJson(u32, ctx.allocator, try parseUnsignedJsonValueAs(u32, value));
                            errdefer ctx.allocator.free(input_json);
                            const input_index = try ctx.appendInput(input_json);
                            break :blk try ctx.buildInputRefJson(input_index);
                        },
                        .object => |object| blk: {
                            if (object.get("Object") != null) return error.InvalidCli;
                            break :blk try ctx.normalizePtbRefOrAddExplicitInput(value, false);
                        },
                        else => error.InvalidCli,
                    },
                    .u64 => return switch (value) {
                        .integer, .number_string, .string => blk: {
                            const input_json = try buildPureUnsignedInputJson(u64, ctx.allocator, try parseUnsignedJsonValueAs(u64, value));
                            errdefer ctx.allocator.free(input_json);
                            const input_index = try ctx.appendInput(input_json);
                            break :blk try ctx.buildInputRefJson(input_index);
                        },
                        .object => |object| blk: {
                            if (object.get("Object") != null) return error.InvalidCli;
                            break :blk try ctx.normalizePtbRefOrAddExplicitInput(value, false);
                        },
                        else => error.InvalidCli,
                    },
                    .u128 => return switch (value) {
                        .integer, .number_string, .string => blk: {
                            const input_json = try buildPureUnsignedInputJson(u128, ctx.allocator, try parseUnsignedJsonValueAs(u128, value));
                            errdefer ctx.allocator.free(input_json);
                            const input_index = try ctx.appendInput(input_json);
                            break :blk try ctx.buildInputRefJson(input_index);
                        },
                        .object => |object| blk: {
                            if (object.get("Object") != null) return error.InvalidCli;
                            break :blk try ctx.normalizePtbRefOrAddExplicitInput(value, false);
                        },
                        else => error.InvalidCli,
                    },
                    .u256 => return switch (value) {
                        .integer, .number_string, .string => blk: {
                            const input_json = try buildPureUnsignedInputJson(u256, ctx.allocator, try parseUnsignedJsonValueAs(u256, value));
                            errdefer ctx.allocator.free(input_json);
                            const input_index = try ctx.appendInput(input_json);
                            break :blk try ctx.buildInputRefJson(input_index);
                        },
                        .object => |object| blk: {
                            if (object.get("Object") != null) return error.InvalidCli;
                            break :blk try ctx.normalizePtbRefOrAddExplicitInput(value, false);
                        },
                        else => error.InvalidCli,
                    },
                    .vector_u8 => return switch (value) {
                        .string, .array => blk: {
                            const bytes = try ptb_bytes_builder.parseRawBytesJsonValue(ctx.allocator, value);
                            defer ctx.allocator.free(bytes);
                            const input_json = try buildPureBytesInputJson(ctx.allocator, bytes);
                            errdefer ctx.allocator.free(input_json);
                            const input_index = try ctx.appendInput(input_json);
                            break :blk try ctx.buildInputRefJson(input_index);
                        },
                        .object => |object| blk: {
                            if (object.get("Object") != null) return error.InvalidCli;
                            break :blk try ctx.normalizePtbRefOrAddExplicitInput(value, false);
                        },
                        else => error.InvalidCli,
                    },
                    .utf8_string, .ascii_string, .object_id, .option => return error.InvalidCli,
                    .vector => return error.InvalidCli,
                    .unsupported => return switch (value) {
                        .object => |object| blk: {
                            if (object.get("Input") != null or object.get("Result") != null or object.get("NestedResult") != null or object.get("Pure") != null or object.get("Object") != null) {
                                break :blk try ctx.normalizePtbRefOrAddExplicitInput(value, false);
                            }
                            return error.InvalidCli;
                        },
                        .string => |string_value| if (std.mem.eql(u8, string_value, "GasCoin"))
                            try ctx.normalizePtbRefOrAddExplicitInput(value, false)
                        else
                            error.InvalidCli,
                        else => error.InvalidCli,
                    },
                }
            }

            fn lowerVectorMoveCallArgument(
                ctx: *@This(),
                value: std.json.Value,
                element_type: std.json.Value,
            ) anyerror![]u8 {
                return switch (value) {
                    .array => |array| {
                        var lowered_elements = std.ArrayListUnmanaged([]u8){};
                        defer {
                            for (lowered_elements.items) |item| ctx.allocator.free(item);
                            lowered_elements.deinit(ctx.allocator);
                        }

                        for (array.items) |item| {
                            try lowered_elements.append(
                                ctx.allocator,
                                try ctx.lowerMoveCallArgumentForNormalizedType(item, element_type),
                            );
                        }

                        const elements_json = try ctx.appendJsonArray(lowered_elements.items);
                        defer ctx.allocator.free(elements_json);

                        const type_json = if (array.items.len == 0) blk: {
                            if (normalizedMoveTypeContainsTypeParameter(element_type)) return error.InvalidCli;
                            break :blk try canonicalNormalizedMoveTypeJson(ctx.allocator, element_type);
                        } else try ctx.allocator.dupe(u8, "null");
                        defer ctx.allocator.free(type_json);

                        const command_json = try std.fmt.allocPrint(
                            ctx.allocator,
                            "{{\"kind\":\"MakeMoveVec\",\"type\":{s},\"elements\":{s}}}",
                            .{ type_json, elements_json },
                        );
                        errdefer ctx.allocator.free(command_json);
                        const command_index = try ctx.appendCommand(command_json);
                        return try ctx.buildResultRefJson(command_index);
                    },
                    .object => |object| blk: {
                        if (object.get("Object") != null) return error.InvalidCli;
                        break :blk try ctx.normalizePtbRefOrAddExplicitInput(value, false);
                    },
                    else => return error.InvalidCli,
                };
            }

            fn lowerMoveCallArgumentForNormalizedType(
                ctx: *@This(),
                value: std.json.Value,
                parameter_type: std.json.Value,
            ) anyerror![]u8 {
                switch (parameter_type) {
                    .string => {
                        const kind = (try classifyNormalizedMoveType(ctx.allocator, parameter_type)) orelse return error.InvalidCli;
                        return try ctx.lowerMoveCallArgumentForKind(value, kind);
                    },
                    .object => |object| {
                        if (object.get("Reference")) |inner| {
                            return try ctx.lowerMoveCallArgumentForNormalizedType(value, inner);
                        }
                        if (object.get("MutableReference")) |inner| {
                            return try ctx.lowerMoveCallArgumentForNormalizedType(value, inner);
                        }
                        if (object.get("Vector")) |inner| {
                            const nested_kind = try classifyNormalizedMoveType(ctx.allocator, inner);
                            if (nested_kind == .u8) return try ctx.lowerMoveCallArgumentForKind(value, .vector_u8);
                            return try ctx.lowerVectorMoveCallArgument(value, inner);
                        }
                        if (try classifyKnownPureStructType(parameter_type)) |_| {
                            switch (value) {
                                .object => |argument_object| {
                                    if (argument_object.get("Object") != null) return error.InvalidCli;
                                    if (argument_object.get("Input") != null or
                                        argument_object.get("Result") != null or
                                        argument_object.get("NestedResult") != null or
                                        argument_object.get("Pure") != null)
                                    {
                                        return try ctx.normalizePtbRefOrAddExplicitInput(value, false);
                                    }
                                },
                                else => {},
                            }

                            const input_json = try buildPureNormalizedValueInputJson(ctx.allocator, value, parameter_type);
                            errdefer ctx.allocator.free(input_json);
                            const input_index = try ctx.appendInput(input_json);
                            return try ctx.buildInputRefJson(input_index);
                        }

                        const kind = (try classifyNormalizedMoveType(ctx.allocator, parameter_type)) orelse return error.InvalidCli;
                        return try ctx.lowerMoveCallArgumentForKind(value, kind);
                    },
                    else => return error.InvalidCli,
                }
            }

            fn lowerAddressArgument(
                ctx: *@This(),
                value: std.json.Value,
            ) ![]u8 {
                switch (value) {
                    .string => |address| {
                        const input_json = try buildPureAddressInputJson(ctx.allocator, address);
                        errdefer ctx.allocator.free(input_json);
                        const input_index = try ctx.appendInput(input_json);
                        return try ctx.buildInputRefJson(input_index);
                    },
                    .object => return try ctx.normalizePtbRefOrAddExplicitInput(value, false),
                    else => return error.InvalidCli,
                }
            }

            fn lowerU64Argument(
                ctx: *@This(),
                value: std.json.Value,
            ) ![]u8 {
                switch (value) {
                    .integer, .number_string, .string => {
                        if (value == .string and std.mem.eql(u8, value.string, "GasCoin")) return error.InvalidCli;
                        const input_json = try buildPureU64InputJson(ctx.allocator, try parseUnsignedJsonValue(value));
                        errdefer ctx.allocator.free(input_json);
                        const input_index = try ctx.appendInput(input_json);
                        return try ctx.buildInputRefJson(input_index);
                    },
                    .object => return try ctx.normalizePtbRefOrAddExplicitInput(value, false),
                    else => return error.InvalidCli,
                }
            }

            fn appendJsonArray(
                ctx: *@This(),
                items: []const []const u8,
            ) ![]u8 {
                var out = std.ArrayList(u8){};
                errdefer out.deinit(ctx.allocator);
                const writer = out.writer(ctx.allocator);
                try writer.writeAll("[");
                for (items, 0..) |item, index| {
                    if (index != 0) try writer.writeAll(",");
                    try writer.writeAll(item);
                }
                try writer.writeAll("]");
                return try out.toOwnedSlice(ctx.allocator);
            }

            fn buildInputsJson(ctx: *@This()) ![]u8 {
                return try ctx.appendJsonArray(ctx.inputs.items);
            }

            fn buildCommandsJson(ctx: *@This()) ![]u8 {
                return try ctx.appendJsonArray(ctx.commands.items);
            }

            fn lowerMoveCallCommand(
                ctx: *@This(),
                command: std.json.Value,
            ) ![]u8 {
                const object = command.object;
                const package_id = object.get("package") orelse return error.InvalidCli;
                const module = object.get("module") orelse return error.InvalidCli;
                const function_name = object.get("function") orelse return error.InvalidCli;
                if (package_id != .string or module != .string or function_name != .string) return error.InvalidCli;

                const normalized_response = try ctx.rpc.getNormalizedMoveFunction(
                    ctx.allocator,
                    package_id.string,
                    module.string,
                    function_name.string,
                );
                defer ctx.allocator.free(normalized_response);

                const normalized_parsed = try std.json.parseFromSlice(std.json.Value, ctx.allocator, normalized_response, .{});
                defer normalized_parsed.deinit();
                if (normalized_parsed.value != .object) return error.InvalidResponse;
                const normalized_result = normalized_parsed.value.object.get("result") orelse return error.InvalidResponse;
                if (normalized_result != .object) return error.InvalidResponse;
                const parameters_value = normalized_result.object.get("parameters") orelse return error.InvalidResponse;
                if (parameters_value != .array) return error.InvalidResponse;
                const raw_type_arguments = if (object.get("typeArguments")) |raw_type_arguments| blk: {
                    if (raw_type_arguments != .array) return error.InvalidCli;
                    break :blk raw_type_arguments.array.items;
                } else &.{};

                var lowered_arguments = std.ArrayListUnmanaged([]u8){};
                defer {
                    for (lowered_arguments.items) |item| ctx.allocator.free(item);
                    lowered_arguments.deinit(ctx.allocator);
                }

                const arguments = if (object.get("arguments")) |raw_arguments| blk: {
                    if (raw_arguments != .array) return error.InvalidCli;
                    break :blk raw_arguments.array.items;
                } else &.{};

                var user_parameter_count: usize = 0;
                for (parameters_value.array.items) |parameter| {
                    const resolved_parameter_json = try substituteNormalizedMoveTypeJson(ctx.allocator, parameter, raw_type_arguments);
                    defer ctx.allocator.free(resolved_parameter_json);
                    const resolved_parameter_parsed = try std.json.parseFromSlice(std.json.Value, ctx.allocator, resolved_parameter_json, .{});
                    defer resolved_parameter_parsed.deinit();
                    if ((try classifyNormalizedMoveType(ctx.allocator, resolved_parameter_parsed.value)) == null) continue;
                    user_parameter_count += 1;
                }
                if (arguments.len != user_parameter_count) return error.InvalidCli;

                var argument_index: usize = 0;
                for (parameters_value.array.items) |parameter| {
                    const resolved_parameter_json = try substituteNormalizedMoveTypeJson(ctx.allocator, parameter, raw_type_arguments);
                    defer ctx.allocator.free(resolved_parameter_json);
                    const resolved_parameter_parsed = try std.json.parseFromSlice(std.json.Value, ctx.allocator, resolved_parameter_json, .{});
                    defer resolved_parameter_parsed.deinit();
                    if ((try classifyNormalizedMoveType(ctx.allocator, resolved_parameter_parsed.value)) == null) continue;
                    try lowered_arguments.append(
                        ctx.allocator,
                        try ctx.lowerMoveCallArgumentForNormalizedType(arguments[argument_index], resolved_parameter_parsed.value),
                    );
                    argument_index += 1;
                }
                const arguments_json = try ctx.appendJsonArray(lowered_arguments.items);
                defer ctx.allocator.free(arguments_json);

                const type_arguments_json = try canonicalMoveTypeArgumentsJson(ctx.allocator, raw_type_arguments);
                defer ctx.allocator.free(type_arguments_json);

                return try std.fmt.allocPrint(
                    ctx.allocator,
                    "{{\"kind\":\"MoveCall\",\"package\":{f},\"module\":{f},\"function\":{f},\"typeArguments\":{s},\"arguments\":{s}}}",
                    .{
                        std.json.fmt(package_id.string, .{}),
                        std.json.fmt(module.string, .{}),
                        std.json.fmt(function_name.string, .{}),
                        type_arguments_json,
                        arguments_json,
                    },
                );
            }

            fn lowerTransferObjectsCommand(
                ctx: *@This(),
                command: std.json.Value,
            ) ![]u8 {
                const object = command.object;
                const objects_value = object.get("objects") orelse return error.InvalidCli;
                const address_value = object.get("address") orelse return error.InvalidCli;
                if (objects_value != .array) return error.InvalidCli;

                var lowered_objects = std.ArrayListUnmanaged([]u8){};
                defer {
                    for (lowered_objects.items) |item| ctx.allocator.free(item);
                    lowered_objects.deinit(ctx.allocator);
                }

                for (objects_value.array.items) |entry| {
                    try lowered_objects.append(ctx.allocator, try ctx.lowerObjectArgument(entry));
                }

                const objects_json = try ctx.appendJsonArray(lowered_objects.items);
                defer ctx.allocator.free(objects_json);
                const address_json = try ctx.lowerAddressArgument(address_value);
                defer ctx.allocator.free(address_json);

                return try std.fmt.allocPrint(
                    ctx.allocator,
                    "{{\"kind\":\"TransferObjects\",\"objects\":{s},\"address\":{s}}}",
                    .{ objects_json, address_json },
                );
            }

            fn lowerSplitCoinsCommand(
                ctx: *@This(),
                command: std.json.Value,
            ) ![]u8 {
                const object = command.object;
                const coin_value = object.get("coin") orelse return error.InvalidCli;
                const amounts_value = object.get("amounts") orelse return error.InvalidCli;
                if (amounts_value != .array) return error.InvalidCli;

                const coin_json = try ctx.lowerObjectArgument(coin_value);
                defer ctx.allocator.free(coin_json);

                var lowered_amounts = std.ArrayListUnmanaged([]u8){};
                defer {
                    for (lowered_amounts.items) |item| ctx.allocator.free(item);
                    lowered_amounts.deinit(ctx.allocator);
                }

                for (amounts_value.array.items) |entry| {
                    try lowered_amounts.append(ctx.allocator, try ctx.lowerU64Argument(entry));
                }

                const amounts_json = try ctx.appendJsonArray(lowered_amounts.items);
                defer ctx.allocator.free(amounts_json);

                return try std.fmt.allocPrint(
                    ctx.allocator,
                    "{{\"kind\":\"SplitCoins\",\"coin\":{s},\"amounts\":{s}}}",
                    .{ coin_json, amounts_json },
                );
            }

            fn lowerMergeCoinsCommand(
                ctx: *@This(),
                command: std.json.Value,
            ) ![]u8 {
                const object = command.object;
                const destination_value = object.get("destination") orelse return error.InvalidCli;
                const sources_value = object.get("sources") orelse return error.InvalidCli;
                if (sources_value != .array) return error.InvalidCli;

                const destination_json = try ctx.lowerObjectArgument(destination_value);
                defer ctx.allocator.free(destination_json);

                var lowered_sources = std.ArrayListUnmanaged([]u8){};
                defer {
                    for (lowered_sources.items) |item| ctx.allocator.free(item);
                    lowered_sources.deinit(ctx.allocator);
                }

                for (sources_value.array.items) |entry| {
                    try lowered_sources.append(ctx.allocator, try ctx.lowerObjectArgument(entry));
                }

                const sources_json = try ctx.appendJsonArray(lowered_sources.items);
                defer ctx.allocator.free(sources_json);

                return try std.fmt.allocPrint(
                    ctx.allocator,
                    "{{\"kind\":\"MergeCoins\",\"destination\":{s},\"sources\":{s}}}",
                    .{ destination_json, sources_json },
                );
            }

            fn lowerMakeMoveVecElement(
                ctx: *@This(),
                value: std.json.Value,
            ) ![]u8 {
                return switch (value) {
                    .string => try ctx.lowerObjectArgument(value),
                    .object => try ctx.normalizePtbRefOrAddExplicitInput(value, false),
                    else => error.InvalidCli,
                };
            }

            fn lowerMakeMoveVecElementForType(
                ctx: *@This(),
                value: std.json.Value,
                element_type: ?std.json.Value,
            ) anyerror![]u8 {
                if (element_type) |resolved_type| {
                    const kind = (try classifyNormalizedMoveType(ctx.allocator, resolved_type)) orelse .object;
                    return switch (kind) {
                        .signer => error.InvalidCli,
                        else => try ctx.lowerMoveCallArgumentForNormalizedType(value, resolved_type),
                    };
                }
                return try ctx.lowerMakeMoveVecElement(value);
            }

            fn canonicalizeMakeMoveVecTypeJson(
                ctx: *@This(),
                raw_type: ?std.json.Value,
            ) ![]u8 {
                const value = raw_type orelse return try ctx.allocator.dupe(u8, "null");
                if (value == .null) return try ctx.allocator.dupe(u8, "null");
                return try canonicalMoveTypeArgumentJson(ctx.allocator, value);
            }

            fn parseOptionalCanonicalMakeMoveVecType(
                ctx: *@This(),
                canonical_type_json: []const u8,
            ) !?std.json.Parsed(std.json.Value) {
                if (std.mem.eql(u8, canonical_type_json, "null")) return null;
                return try std.json.parseFromSlice(std.json.Value, ctx.allocator, canonical_type_json, .{});
            }

            fn lowerMakeMoveVecCommand(
                ctx: *@This(),
                command: std.json.Value,
            ) ![]u8 {
                const object = command.object;
                const elements_value = object.get("elements") orelse return error.InvalidCli;
                if (elements_value != .array) return error.InvalidCli;
                const type_json = try ctx.canonicalizeMakeMoveVecTypeJson(object.get("type"));
                defer ctx.allocator.free(type_json);

                const parsed_type = try ctx.parseOptionalCanonicalMakeMoveVecType(type_json);
                defer if (parsed_type) |*value| value.deinit();
                const element_type = if (parsed_type) |value| value.value else null;

                var lowered_elements = std.ArrayListUnmanaged([]u8){};
                defer {
                    for (lowered_elements.items) |item| ctx.allocator.free(item);
                    lowered_elements.deinit(ctx.allocator);
                }

                for (elements_value.array.items) |entry| {
                    try lowered_elements.append(
                        ctx.allocator,
                        try ctx.lowerMakeMoveVecElementForType(entry, element_type),
                    );
                }

                const elements_json = try ctx.appendJsonArray(lowered_elements.items);
                defer ctx.allocator.free(elements_json);

                return try std.fmt.allocPrint(
                    ctx.allocator,
                    "{{\"kind\":\"MakeMoveVec\",\"type\":{s},\"elements\":{s}}}",
                    .{ type_json, elements_json },
                );
            }

            fn lowerPublishCommand(
                ctx: *@This(),
                command: std.json.Value,
            ) ![]u8 {
                const object = command.object;
                const modules_value = object.get("modules") orelse return error.InvalidCli;
                const dependencies_value = object.get("dependencies") orelse return error.InvalidCli;
                if (modules_value != .array or dependencies_value != .array) return error.InvalidCli;

                const modules_json = try stringifyJsonValueAlloc(ctx.allocator, modules_value);
                defer ctx.allocator.free(modules_json);
                const dependencies_json = try stringifyJsonValueAlloc(ctx.allocator, dependencies_value);
                defer ctx.allocator.free(dependencies_json);

                return try std.fmt.allocPrint(
                    ctx.allocator,
                    "{{\"kind\":\"Publish\",\"modules\":{s},\"dependencies\":{s}}}",
                    .{ modules_json, dependencies_json },
                );
            }

            fn lowerUpgradeCommand(
                ctx: *@This(),
                command: std.json.Value,
            ) ![]u8 {
                const object = command.object;
                const modules_value = object.get("modules") orelse return error.InvalidCli;
                const dependencies_value = object.get("dependencies") orelse return error.InvalidCli;
                const package_value = object.get("package") orelse return error.InvalidCli;
                const ticket_value = object.get("ticket") orelse return error.InvalidCli;
                if (modules_value != .array or dependencies_value != .array or package_value != .string) return error.InvalidCli;

                const modules_json = try stringifyJsonValueAlloc(ctx.allocator, modules_value);
                defer ctx.allocator.free(modules_json);
                const dependencies_json = try stringifyJsonValueAlloc(ctx.allocator, dependencies_value);
                defer ctx.allocator.free(dependencies_json);
                const ticket_json = try ctx.lowerObjectArgument(ticket_value);
                defer ctx.allocator.free(ticket_json);

                return try std.fmt.allocPrint(
                    ctx.allocator,
                    "{{\"kind\":\"Upgrade\",\"modules\":{s},\"dependencies\":{s},\"package\":{f},\"ticket\":{s}}}",
                    .{
                        modules_json,
                        dependencies_json,
                        std.json.fmt(package_value.string, .{}),
                        ticket_json,
                    },
                );
            }

            fn lowerCommand(
                ctx: *@This(),
                command: std.json.Value,
            ) ![]u8 {
                if (command != .object) return error.InvalidCli;
                const kind = command.object.get("kind") orelse return error.InvalidCli;
                if (kind != .string) return error.InvalidCli;

                if (std.mem.eql(u8, kind.string, "MoveCall")) {
                    return try ctx.lowerMoveCallCommand(command);
                }
                if (std.mem.eql(u8, kind.string, "TransferObjects")) {
                    return try ctx.lowerTransferObjectsCommand(command);
                }
                if (std.mem.eql(u8, kind.string, "SplitCoins")) {
                    return try ctx.lowerSplitCoinsCommand(command);
                }
                if (std.mem.eql(u8, kind.string, "MergeCoins")) {
                    return try ctx.lowerMergeCoinsCommand(command);
                }
                if (std.mem.eql(u8, kind.string, "MakeMoveVec")) {
                    return try ctx.lowerMakeMoveVecCommand(command);
                }
                if (std.mem.eql(u8, kind.string, "Publish")) {
                    return try ctx.lowerPublishCommand(command);
                }
                if (std.mem.eql(u8, kind.string, "Upgrade")) {
                    return try ctx.lowerUpgradeCommand(command);
                }
                return error.InvalidCli;
            }
        };

        var lowering = LoweringContext{
            .rpc = self,
            .allocator = allocator,
        };
        defer lowering.deinit();

        for (parsed.value.array.items) |command| {
            try lowering.commands.append(allocator, try lowering.lowerCommand(command));
        }

        var owned = OwnedLocalProgrammableTransactionParts{
            .inputs_json = try lowering.buildInputsJson(),
            .commands_json = try lowering.buildCommandsJson(),
            .sender = try allocator.dupe(u8, sender),
            .gas_data_json = try self.buildGasDataJson(
                allocator,
                sender,
                gas_payment_json,
                gas_price,
                gas_budget,
            ),
            .expiration_json = if (expiration_json) |value| try allocator.dupe(u8, value) else null,
        };
        errdefer owned.deinit(allocator);
        return owned;
    }

