    pub fn getAllEventsWithRequest(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        request: EventPageRequest,
    ) !event_result.OwnedEventPage {
        var collected = std.ArrayList(event_result.OwnedEventEntry).empty;
        errdefer {
            for (collected.items) |*entry| entry.deinit(allocator);
            collected.deinit(allocator);
        }

        var cursor_tx_digest_owned: ?[]u8 = if (request.cursor_tx_digest) |value| try allocator.dupe(u8, value) else null;
        defer if (cursor_tx_digest_owned) |value| allocator.free(value);
        var cursor_event_seq = request.cursor_event_seq;

        while (true) {
            var page = try self.getEventsPageWithRequest(
                allocator,
                .{
                    .filter = request.filter,
                    .cursor_tx_digest = if (cursor_tx_digest_owned) |value| value else null,
                    .cursor_event_seq = cursor_event_seq,
                    .limit = request.limit,
                    .descending_order = request.descending_order,
                },
            );
            defer page.deinit(allocator);

            for (page.entries) |entry| {
                try collected.append(allocator, try entry.clone(allocator));
            }

            if (!page.has_next_page) break;
            const next_tx_digest = page.next_cursor_tx_digest orelse return error.InvalidResponse;
            const next_event_seq = page.next_cursor_event_seq orelse return error.InvalidResponse;
            if (cursor_tx_digest_owned) |value| allocator.free(value);
            cursor_tx_digest_owned = try allocator.dupe(u8, next_tx_digest);
            cursor_event_seq = next_event_seq;
        }

        return .{
            .entries = try collected.toOwnedSlice(allocator),
            .next_cursor_tx_digest = null,
            .next_cursor_event_seq = null,
            .has_next_page = false,
        };
    }

    pub fn runObjectQuery(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        query: ObjectQuery,
    ) ![]u8 {
        return switch (query) {
            .get => |spec| switch (spec.options) {
                .none => try dupeOwnedJsonResponse(self.allocator, allocator, try self.getObject(spec.object_id, null)),
                .json => |options_json| try dupeOwnedJsonResponse(self.allocator, allocator, try self.getObject(spec.object_id, options_json)),
                .typed => |options| try dupeOwnedJsonResponse(self.allocator, allocator, try self.getObjectWithOptions(spec.object_id, options)),
            },
            .dynamic_fields_page => |spec| try dupeOwnedJsonResponse(
                self.allocator,
                allocator,
                try self.getDynamicFieldsWithRequest(spec.parent_object_id, spec.request),
            ),
            .dynamic_fields_all => |spec| blk: {
                var page = try self.getAllDynamicFieldsWithRequest(allocator, spec.parent_object_id, spec.request);
                defer page.deinit(allocator);
                break :blk try std.fmt.allocPrint(allocator, "{f}", .{std.json.fmt(page, .{})});
            },
            .dynamic_field_object => |spec| switch (spec.name) {
                .json => |name_json| try dupeOwnedJsonResponse(
                    self.allocator,
                    allocator,
                    try self.getDynamicFieldObject(spec.parent_object_id, name_json),
                ),
                .typed => |name| try dupeOwnedJsonResponse(
                    self.allocator,
                    allocator,
                    try self.getDynamicFieldObjectWithName(spec.parent_object_id, name),
                ),
            },
        };
    }

    pub fn runObjectQueryAndSummarize(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        query: ObjectQuery,
    ) !ObjectQuerySummary {
        return switch (query) {
            .get => |spec| switch (spec.options) {
                .none => .{
                    .object = try self.getObjectAndSummarizeWithOptions(
                        allocator,
                        spec.object_id,
                        objectDataOptionsForSummaries(.{}),
                    ),
                },
                .json => |options_json| .{
                    .object = try self.getObjectAndSummarize(allocator, spec.object_id, options_json),
                },
                .typed => |options| .{
                    .object = try self.getObjectAndSummarizeWithOptions(
                        allocator,
                        spec.object_id,
                        objectDataOptionsForSummaries(options),
                    ),
                },
            },
            .dynamic_fields_page => |spec| .{
                .dynamic_fields = try self.getDynamicFieldsPageWithRequest(
                    allocator,
                    spec.parent_object_id,
                    spec.request,
                ),
            },
            .dynamic_fields_all => |spec| .{
                .dynamic_fields = try self.getAllDynamicFieldsWithRequest(
                    allocator,
                    spec.parent_object_id,
                    spec.request,
                ),
            },
            .dynamic_field_object => |spec| switch (spec.name) {
                .json => |name_json| .{
                    .object = try self.getDynamicFieldObjectAndSummarize(
                        allocator,
                        spec.parent_object_id,
                        name_json,
                    ),
                },
                .typed => |name| .{
                    .object = try self.getDynamicFieldObjectAndSummarizeWithName(
                        allocator,
                        spec.parent_object_id,
                        name,
                    ),
                },
            },
        };
    }

    pub fn runObjectQueryAction(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        query: ObjectQuery,
        action: ObjectQueryAction,
    ) !ObjectQueryActionResult {
        return switch (action) {
            .raw => .{ .raw = try self.runObjectQuery(allocator, query) },
            .summarize => .{ .summarized = try self.runObjectQueryAndSummarize(allocator, query) },
        };
    }

    pub fn runMoveQuery(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        query: MoveQuery,
    ) ![]u8 {
        return switch (query) {
            .function => |spec| try self.getNormalizedMoveFunction(
                allocator,
                spec.package_id,
                spec.module,
                spec.function_name,
            ),
            .module => |spec| try self.getNormalizedMoveModule(
                allocator,
                spec.package_id,
                spec.module,
            ),
            .package => |spec| try self.getNormalizedMoveModulesByPackage(
                allocator,
                spec.package_id,
            ),
        };
    }

    pub fn runMoveQueryAndSummarize(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        query: MoveQuery,
    ) !MoveQuerySummary {
        return switch (query) {
            .function => |spec| blk: {
                const response = try self.getNormalizedMoveFunction(
                    allocator,
                    spec.package_id,
                    spec.module,
                    spec.function_name,
                );
                defer allocator.free(response);
                break :blk .{
                    .function = try self.summarizeMoveFunctionResponse(
                        allocator,
                        spec.package_id,
                        spec.module,
                        spec.function_name,
                        response,
                        spec.type_arguments_json,
                        spec.arguments_json,
                        spec.indexed_arguments_json,
                        spec.indexed_object_arguments_json,
                        spec.owner_address,
                        spec.signer_selector,
                    ),
                };
            },
            .module => |spec| blk: {
                const response = try self.getNormalizedMoveModule(
                    allocator,
                    spec.package_id,
                    spec.module,
                );
                defer allocator.free(response);
                break :blk .{
                    .module = try self.summarizeMoveModuleResponse(
                        allocator,
                        spec.package_id,
                        spec.module,
                        response,
                    ),
                };
            },
            .package => |spec| blk: {
                const response = try self.getNormalizedMoveModulesByPackage(
                    allocator,
                    spec.package_id,
                );
                defer allocator.free(response);
                break :blk .{
                    .package = try self.summarizeMovePackageResponse(
                        allocator,
                        spec.package_id,
                        response,
                    ),
                };
            },
        };
    }

    pub fn runMoveQueryAction(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
