                },
                .session = .{ .kind = .remote_signer, .session_id = "pending-auto-gas-selected" },
                .session_challenge = .{
                    .passkey = .{
                        .rp_id = "wallet.example",
                        .challenge_b64url = "challenge-auto-gas-selected",
                    },
                },
                .session_action = .execute,
                .session_supports_execute = false,
