        fn call(context: *anyopaque, alloc: std.mem.Allocator, req: RpcRequest) ![]u8 {
            const count = @as(*usize, @ptrCast(@alignCast(context)));
            if (std.mem.eql(u8, req.method, "suix_getOwnedObjects")) {
                return alloc.dupe(
                    u8,
